          </p>
        </div>
        <div className="space-y-2">
          <Label>Coverage Level</Label>
          <Select
            value={inputs.coverageLevel}
            onValueChange={(v) => handleInputChange("coverageLevel", v)}
          >
            <SelectTrigger>
              <SelectValue />
