            <SelectContent>
              <SelectItem value="basic">Basic (1.5%)</SelectItem>
              <SelectItem value="standard">Standard (2.5%)</SelectItem>
              <SelectItem value="premium">Premium (4.0%)</SelectItem>
            </SelectContent>
