      {
        label: "1. Measure",
        explanation:
          "Calculate the volume: 5 m ├ù 4 m ├ù 3 m = 60 m┬│. Multiply by BTU per cubic meter (500 BTU): 60 ├ù 500 = 30,000 BTU base requirement.",
      },
      {
        label: "2. Waste",
        explanation:
          "Add 10% waste margin: 30,000 ├ù 1.10 = 33,000 BTU total requirement.",
      },
      {
        label: "3. Order",
        explanation:
          "Divide total BTU by material unit capacity (10,000 BTU): 33,000 ├╖ 10,000 = 3.3 ΓåÆ round up to 4 units to order.",
      },
    ],
    result: "Final Order: 4 Units of standard size HVAC material.",
  };

  // --- 3. FORMULA DEFINITION ---
  const formula = {
    title: "Calculation Formula",
    formula:
      "Total BTU = Length ├ù Width ├ù Height ├ù BTU per unit volume ├ù (1 + Waste Margin)",
    variables: [
      { symbol: "Length", description: "Length of the space (meters or feet)" },
      { symbol: "Width", description: "Width of the space (meters or feet)" },
      { symbol: "Height", description: "Height of the space (meters or feet)" },
      {
        symbol: "BTU per unit volume",
        description:
          "Heating or cooling BTU required per cubic meter or cubic foot",
      },
      {
        symbol: "Waste Margin",
        description: "Additional percentage to cover inefficiencies and waste",
      },
