    const wastePercent = parseFloat(inputs.waste);
    const pricePerUnit = parseFloat(inputs.price);
    const unit = inputs.unit;
    const matSize = inputs.materialSize;

    if (
      isNaN(treadLengthNum) ||
      isNaN(treadWidthNum) ||
      isNaN(riserHeightNum) ||
      treadLengthNum <= 0 ||
      treadWidthNum <= 0 ||
      riserHeightNum <= 0
