  const [toUnit, setToUnit] = useState("mpg(US)");

  // 2. LOGIC
  // Conversion formulas:
  // L/100km to mpg(US): mpg = 235.214583 / L/100km
  // mpg(US) to L/100km: L/100km = 235.214583 / mpg
