      label = "Casual Sipper";
      icon = <Meh />;
      color = "text-blue-600";
      subtext = "You enjoy coffee but itΓÇÖs not running your life. Keep it chill!";
    } else if (score < 25) {
      label = "Daily Drinker";
      icon = <Coffee />;
      color = "text-yellow-600";
