        ],
        result: "John's estimated body fat percentage is approximately 21.9%, categorized as 'Average' for males.",
      }}
      relatedCalculators={[
        {
          title: "BMI ΓÇö Body Mass Index Calculator",
          url: "/health/bmi-body-mass-index",
