import { useState, useMemo } from "react";
import CalculatorVerticalLayout from '@/components/templates/CalculatorVerticalLayout';
import { Card, CardContent } from "@/components/ui/card";
import { Label } from "@/components/ui/label";
import { Input } from "@/components/ui/input";
import { Button } from "@/components/ui/button";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import {
  Calculator,
  RotateCcw,
} from "lucide-react";
import useFaqJsonLd from "@/hooks/useFaqJsonLd";

export default function FatIntakeRangeAmdrCalculator() {
  // 1. STATE (Imperial Default)
  const [unit, setUnit] = useState("imperial");
  const [inputs, setInputs] = useState({
    weight: "", // lbs or kg
    heightFeet: "", // feet (imperial only)
    heightInches: "", // inches (imperial only)
    heightCm: "", // cm (metric only)
    age: "",
    sex: "female", // female or male
    activityLevel: "sedentary", // sedentary, light, moderate, active, very active
    totalCalories: "", // optional, user can input total daily calories to get fat grams range
  });

  // Helper: Convert height to meters
  function heightMeters() {
    if (unit === "imperial") {
      const feet = parseFloat(inputs.heightFeet || "0");
      const inches = parseFloat(inputs.heightInches || "0");
      if (feet === 0 && inches === 0) return 0;
      return (feet * 12 + inches) * 0.0254;
    } else {
      const cm = parseFloat(inputs.heightCm || "0");
      if (cm === 0) return 0;
      return cm / 100;
    }
  }

  // Helper: Convert weight to kg
  function weightKg() {
    const w = parseFloat(inputs.weight || "0");
    if (w === 0) return 0;
    return unit === "imperial" ? w * 0.45359237 : w;
  }

  // Helper: Calculate BMR (Mifflin-St Jeor Equation)
  function calculateBMR() {
    const weight = weightKg();
    const height = heightMeters() * 100; // cm
    const age = parseInt(inputs.age || "0");
    if (weight === 0 || height === 0 || age === 0) return 0;

    if (inputs.sex === "male") {
      return 10 * weight + 6.25 * height - 5 * age + 5;
    } else {
      return 10 * weight + 6.25 * height - 5 * age - 161;
    }
  }

  // Helper: Activity factor based on activity level
  function activityFactor() {
    switch (inputs.activityLevel) {
      case "sedentary":
        return 1.2;
      case "light":
        return 1.375;
      case "moderate":
        return 1.55;
      case "active":
        return 1.725;
      case "very active":
        return 1.9;
      default:
        return 1.2;
    }
  }

  // 2. LOGIC
  const results = useMemo(() => {
    // Validate inputs
    const weight = weightKg();
    const height = heightMeters();
    const age = parseInt(inputs.age || "0");
    if (weight === 0 || height === 0 || age === 0) {
      return { value: 0, label: "Please enter valid inputs", category: "" };
    }

    // Calculate Total Daily Energy Expenditure (TDEE)
    const bmr = calculateBMR();
    const tdee = bmr * activityFactor();

    // Use user input totalCalories if provided and valid
    const totalCalories = parseFloat(inputs.totalCalories || "");
    const calories = totalCalories > 0 ? totalCalories : tdee;

    // AMDR for fat: 20-35% of total calories from fat (per Health Canada & US Dietary Guidelines)
    // 1 gram fat = 9 kcal
    const fatMinCalories = calories * 0.20;
    const fatMaxCalories = calories * 0.35;
    const fatMinGrams = fatMinCalories / 9;
    const fatMaxGrams = fatMaxCalories / 9;

    // Format results with 1 decimal place
    const fatMinGramsFormatted = fatMinGrams.toFixed(1);
    const fatMaxGramsFormatted = fatMaxGrams.toFixed(1);

    return {
      value: `${fatMinGramsFormatted} - ${fatMaxGramsFormatted} g`,
      label: `Recommended Fat Intake Range (20-35% of total calories)`,
      category: "AMDR",
    };
  }, [inputs, unit]);

  // 3. FAQS
  const faqs = [
    {
      question: "What is the Acceptable Macronutrient Distribution Range (AMDR) for fat?",
      answer:
        "The AMDR for fat is a range of intake that is associated with reduced risk of chronic diseases while providing adequate essential fatty acids and fat-soluble vitamins. For adults, Health Canada and the US Dietary Guidelines recommend that 20-35% of total daily calories come from fat. This range supports hormonal health, brain function, and satiety.",
    },
    {
      question: "How do I interpret my fat intake range result?",
      answer:
        "The result shows the recommended daily fat intake in grams based on your estimated total daily calorie needs. Staying within this range helps ensure you consume enough fat for essential bodily functions without exceeding calories that could lead to weight gain. Adjust your fat intake according to your health goals and dietary preferences.",
    },
    {
      question: "Can I use this calculator if I don't know my total daily calories?",
      answer:
        "Yes. If you do not input your total daily calories, the calculator estimates your calorie needs using the Mifflin-St Jeor equation for Basal Metabolic Rate (BMR) adjusted by your activity level. For more precise results, you can input your known calorie intake.",
    },
    {
      question: "Are all fats equally healthy within the AMDR?",
      answer:
        "No. While the AMDR defines the total fat intake range, the quality of fats matters. Unsaturated fats from sources like nuts, seeds, fish, and vegetable oils are beneficial, whereas trans fats and excessive saturated fats should be limited. Balancing fat types supports cardiovascular and metabolic health.",
    },
  ];
  const faqJsonLd = useFaqJsonLd(faqs);

  // Handlers for inputs
  function handleInputChange(
    e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>,
    field: string
  ) {
    setInputs((prev) => ({
      ...prev,
      [field]: e.target.value,
    }));
  }

  // Reset inputs
  function resetInputs() {
    setInputs({
      weight: "",
      heightFeet: "",
      heightInches: "",
      heightCm: "",
      age: "",
      sex: "female",
      activityLevel: "sedentary",
      totalCalories: "",
    });
  }

  const widget = (
    <div className="space-y-6">
      {/* Unit Switcher & Inputs */}
      <div className="space-y-4">
        <div className="flex items-center justify-between">
          <Label className="text-slate-700 dark:text-slate-300">Unit System</Label>
          <Select value={unit} onValueChange={setUnit}>
            <SelectTrigger className="w-[180px]">
              <SelectValue />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="imperial">Imperial (US/Canada)</SelectItem>
              <SelectItem value="metric">Metric (International)</SelectItem>
            </SelectContent>
          </Select>
        </div>

        {/* Weight Input */}
        <div>
          <Label htmlFor="weight" className="text-slate-700 dark:text-slate-300">
            Weight ({unit === "imperial" ? "lbs" : "kg"})
          </Label>
          <Input
            id="weight"
            type="number"
            min={1}
            step="any"
            value={inputs.weight}
            onChange={(e) => handleInputChange(e, "weight")}
            placeholder={unit === "imperial" ? "e.g., 150" : "e.g., 68"}
          />
        </div>

        {/* Height Inputs */}
        {unit === "imperial" ? (
          <div className="flex space-x-4">
            <div className="flex-1">
              <Label htmlFor="heightFeet" className="text-slate-700 dark:text-slate-300">
                Height (feet)
              </Label>
              <Input
                id="heightFeet"
                type="number"
                min={0}
                step="1"
                value={inputs.heightFeet}
                onChange={(e) => handleInputChange(e, "heightFeet")}
                placeholder="5"
              />
            </div>
            <div className="flex-1">
              <Label htmlFor="heightInches" className="text-slate-700 dark:text-slate-300">
                Height (inches)
              </Label>
              <Input
                id="heightInches"
                type="number"
                min={0}
                max={11}
                step="1"
                value={inputs.heightInches}
                onChange={(e) => handleInputChange(e, "heightInches")}
                placeholder="8"
              />
            </div>
          </div>
        ) : (
          <div>
            <Label htmlFor="heightCm" className="text-slate-700 dark:text-slate-300">
              Height (cm)
            </Label>
            <Input
              id="heightCm"
              type="number"
              min={1}
              step="any"
              value={inputs.heightCm}
              onChange={(e) => handleInputChange(e, "heightCm")}
              placeholder="e.g., 173"
            />
          </div>
        )}

        {/* Age Input */}
        <div>
          <Label htmlFor="age" className="text-slate-700 dark:text-slate-300">
            Age (years)
          </Label>
          <Input
            id="age"
            type="number"
            min={1}
            step="1"
            value={inputs.age}
            onChange={(e) => handleInputChange(e, "age")}
            placeholder="e.g., 30"
          />
        </div>

        {/* Sex Select */}
        <div>
          <Label htmlFor="sex" className="text-slate-700 dark:text-slate-300">
            Sex
          </Label>
          <select
            id="sex"
            value={inputs.sex}
            onChange={(e) => handleInputChange(e, "sex")}
            className="w-full rounded-md border border-slate-300 dark:border-slate-700 bg-white dark:bg-slate-900 text-slate-900 dark:text-white p-2"
          >
            <option value="female">Female</option>
            <option value="male">Male</option>
          </select>
        </div>

        {/* Activity Level Select */}
        <div>
          <Label htmlFor="activityLevel" className="text-slate-700 dark:text-slate-300">
            Activity Level
          </Label>
          <select
            id="activityLevel"
            value={inputs.activityLevel}
            onChange={(e) => handleInputChange(e, "activityLevel")}
            className="w-full rounded-md border border-slate-300 dark:border-slate-700 bg-white dark:bg-slate-900 text-slate-900 dark:text-white p-2"
          >
            <option value="sedentary">Sedentary (little or no exercise)</option>
            <option value="light">Lightly active (light exercise 1-3 days/week)</option>
            <option value="moderate">Moderately active (moderate exercise 3-5 days/week)</option>
            <option value="active">Active (hard exercise 6-7 days/week)</option>
            <option value="very active">Very active (very hard exercise & physical job)</option>
          </select>
        </div>

        {/* Optional Total Calories Input */}
        <div>
          <Label htmlFor="totalCalories" className="text-slate-700 dark:text-slate-300">
            Total Daily Calories (optional)
          </Label>
          <Input
            id="totalCalories"
            type="number"
            min={0}
            step="any"
            value={inputs.totalCalories}
            onChange={(e) => handleInputChange(e, "totalCalories")}
            placeholder="e.g., 2000"
          />
          <p className="text-xs italic text-slate-500 dark:text-slate-400 mt-1">
            If left blank, estimated calories will be used.
          </p>
        </div>
      </div>

      {/* Buttons */}
      <div className="flex flex-col sm:flex-row gap-3 pt-4">
        <Button
          className="flex-1 h-11 bg-blue-600 hover:bg-blue-700 text-white font-semibold shadow-md"
          onClick={() => {
            // Just trigger recalculation by updating inputs state (no-op here)
            setInputs((prev) => ({ ...prev }));
          }}
        >
          <Calculator className="mr-2 h-4 w-4" /> Calculate
        </Button>
        <Button
          variant="outline"
          onClick={resetInputs}
          className="flex-1 h-11 hover:bg-slate-100 dark:hover:bg-slate-800"
        >
          <RotateCcw className="mr-2 h-4 w-4" /> Reset
        </Button>
      </div>

      {/* Results (High Contrast for Dark Mode) */}
      {results.value !== 0 && results.value !== "Please enter valid inputs" && (
        <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4">
          <Card className="bg-gradient-to-br from-blue-50 to-indigo-100 dark:from-slate-900 dark:to-slate-950 border-blue-200 shadow-lg">
            <CardContent className="p-8 text-center">
              <p className="text-sm font-bold text-blue-900 dark:text-blue-100 mb-3 uppercase tracking-wider">
                Your Result
              </p>
              <p className="text-5xl font-extrabold text-blue-900 dark:text-white">
                {results.value}
              </p>
              <p className="text-slate-600 dark:text-slate-300 mt-2 font-medium">
                {results.label}
              </p>
              {results.category && (
                <div className="mt-4 inline-flex items-center px-3 py-1 rounded-full bg-white/50 dark:bg-slate-800 border border-blue-200 dark:border-slate-700 text-blue-800 dark:text-blue-300 text-sm font-bold">
                  {results.category}
                </div>
              )}
            </CardContent>
          </Card>
        </div>
      )}

      {/* Show validation message if inputs invalid */}
      {results.value === "Please enter valid inputs" && (
        <p className="text-red-600 dark:text-red-400 font-semibold mt-4 text-center">
          Please fill in all required fields with valid values.
        </p>
      )}
    </div>
  );

  const editorial = (
    <div className="space-y-12">
      {/* MANDATORY "WHAT IS" SECTION */}
      <section id="what-is" className="scroll-mt-32">
        <h2 className="text-3xl font-bold mb-4 text-slate-900 dark:text-slate-100">
          What is the Fat Intake Range (AMDR)?
        </h2>
        <p className="text-slate-700 dark:text-slate-300 leading-relaxed mb-4">
          The Acceptable Macronutrient Distribution Range (AMDR) for fat is a scientifically
          established range of daily fat intake expressed as a percentage of total calories.
          It is designed to provide adequate essential fatty acids and fat-soluble vitamins
          while minimizing the risk of chronic diseases such as cardiovascular disease and
          obesity. In both Canada and the United States, the AMDR for fat for adults is set
          between 20% and 35% of total daily calories.
        </p>
        <p className="text-slate-700 dark:text-slate-300 leading-relaxed mb-4">
          Dietary fats play crucial roles beyond energy provision. They are vital for hormone
          production, cell membrane integrity, brain function, and absorption of fat-soluble
          vitamins (A, D, E, and K). Consuming fats within the AMDR supports these physiological
          functions while helping maintain a healthy weight and metabolic profile. Deviating
          significantly below or above this range can lead to nutrient deficiencies or increased
          health risks.
        </p>
        <p className="text-slate-700 dark:text-slate-300 leading-relaxed mb-4">
          The AMDR is not a fixed target but a flexible range that can be adjusted based on
          individual health goals, medical conditions, and dietary preferences. For example,
          athletes or individuals on ketogenic diets may consume fat at the higher end or
          slightly above the AMDR, while others focusing on weight loss might aim for the
          lower end. This calculator helps you estimate your personalized fat intake range
          based on your calorie needs.
        </p>
        <p className="text-slate-700 dark:text-slate-300 leading-relaxed">
          It is important to emphasize not only the quantity but also the quality of fats
          consumed. Unsaturated fats from sources like nuts, seeds, avocados, and fatty fish
          are encouraged, whereas trans fats and excessive saturated fats should be limited
          to promote cardiovascular health.
        </p>
      </section>

      <section id="how-to-use" className="scroll-mt-32">
        <h2 className="text-3xl font-bold mb-4 text-slate-900 dark:text-slate-100">
          How to Use This Calculator
        </h2>
        <p className="text-slate-700 dark:text-slate-300 leading-relaxed mb-4">
          This calculator estimates your recommended daily fat intake range in grams based
          on your personal characteristics and lifestyle. It uses your weight, height, age,
          sex, and activity level to estimate your total daily calorie needs, then calculates
          20-35% of those calories as fat calories and converts them to grams.
        </p>
        <ul className="list-disc pl-5 space-y-2 text-slate-700 dark:text-slate-300">
          <li>
            <strong>Weight:</strong> Enter your current weight in pounds (lbs) or kilograms (kg)
            depending on your selected unit system.
          </li>
          <li>
            <strong>Height:</strong> Enter your height in feet and inches (imperial) or centimeters
            (metric).
          </li>
          <li>
            <strong>Age and Sex:</strong> Provide your age in years and select your biological sex,
            which affects basal metabolic rate calculations.
          </li>
          <li>
            <strong>Activity Level:</strong> Choose your typical daily activity level to adjust
            your calorie needs accordingly.
          </li>
          <li>
            <strong>Total Daily Calories (optional):</strong> If you know your exact daily calorie
            intake, enter it here to get a more precise fat intake range.
          </li>
        </ul>
        <p className="text-slate-700 dark:text-slate-300 leading-relaxed mt-4">
          After entering your information, click "Calculate" to see your personalized fat intake
          range. Use this range to guide your dietary fat consumption for optimal health.
        </p>
      </section>

      <section id="faq" className="scroll-mt-32">
        <h2 className="text-3xl font-bold mb-4 text-slate-900 dark:text-slate-100">
          Frequently Asked Questions
        </h2>
        <ul className="space-y-6">
          {faqs.map((item, i) => (
            <li
              key={i}
              className="border-b border-slate-200 dark:border-slate-800 pb-4 last:border-0"
            >
              <h3 className="font-bold text-xl text-slate-900 dark:text-slate-100 mb-2">
                {item.question}
              </h3>
              <p className="text-slate-600 dark:text-slate-400 leading-relaxed">{item.answer}</p>
            </li>
          ))}
        </ul>
      </section>

      <section id="references" className="scroll-mt-32">
        <h2 className="text-3xl font-bold mb-4 text-slate-900 dark:text-slate-100">
          Trusted References
        </h2>
        <ul className="space-y-4">
          <li className="block">
            <a
              href="https://www.canada.ca/en/health-canada/services/food-nutrition/healthy-eating/dietary-reference-intakes/energy.html"
              target="_blank"
              rel="noopener noreferrer"
              className="text-blue-600 font-bold hover:underline text-lg"
            >
              1. Health Canada - Dietary Reference Intakes for Energy
            </a>
            <p className="text-slate-500 text-sm mt-1">
              Official Canadian guidelines on energy and macronutrient intake ranges.
            </p>
          </li>
          <li className="block">
            <a
              href="https://www.nal.usda.gov/fnic/dietary-reference-intakes"
              target="_blank"
              rel="noopener noreferrer"
              className="text-blue-600 font-bold hover:underline text-lg"
            >
              2. USDA Dietary Reference Intakes (DRIs)
            </a>
            <p className="text-slate-500 text-sm mt-1">
              Comprehensive nutrient intake recommendations from the US National Academies.
            </p>
          </li>
          <li className="block">
            <a
              href="https://www.nhlbi.nih.gov/health/educational/lose_wt/eat/calories.htm"
              target="_blank"
              rel="noopener noreferrer"
              className="text-blue-600 font-bold hover:underline text-lg"
            >
              3. NIH - Calories and Weight Management
            </a>
            <p className="text-slate-500 text-sm mt-1">
              Information on calorie needs and macronutrient distribution from the National Heart, Lung, and Blood Institute.
            </p>
          </li>
          <li className="block">
            <a
              href="https://www.healthline.com/nutrition/healthy-fats"
              target="_blank"
              rel="noopener noreferrer"
              className="text-blue-600 font-bold hover:underline text-lg"
            >
              4. Healthline - Healthy Fats Explained
            </a>
            <p className="text-slate-500 text-sm mt-1">
              Educational content on types of fats and their health impacts.
            </p>
          </li>
        </ul>
      </section>
    </div>
  );

  return (
    <CalculatorVerticalLayout
      title="Fat Intake Range (AMDR)"
      description="Determine healthy fat intake ranges based on AMDR. Ensure hormonal health and satiety by consuming the right amount of dietary fats."
      widget={widget}
      editorial={editorial}
      jsonLd={faqJsonLd}
      formula={{
        title: "The Math Formula",
        formula:
          "Fat Intake Range (g) = (Total Calories ├ù Fat % Range) ├╖ 9 kcal/g",
        variables: [
          {
            symbol: "Total Calories",
            description:
              "Your estimated or actual total daily calorie intake (kcal)",
          },
          {
            symbol: "Fat % Range",
            description:
              "Acceptable Macronutrient Distribution Range for fat (20% to 35%)",
          },
          {
            symbol: "9 kcal/g",
            description: "Calories per gram of fat",
          },
        ],
      }}
      example={{
        title: "Real-World Example",
        scenario:
          "A 30-year-old female, 5 feet 6 inches tall, weighing 150 lbs, moderately active, with estimated daily calories of 2,000 kcal.",
        steps: [
          {
            label: "Step 1",
            explanation:
              "Calculate total calories (estimated as 2,000 kcal based on inputs).",
          },
          {
            label: "Step 2",
            explanation:
              "Calculate fat intake range: 20-35% of 2,000 kcal = 400-700 kcal from fat.",
          },
          {
            label: "Step 3",
            explanation:
              "Convert calories to grams: 400 ├╖ 9 = 44.4 g, 700 ├╖ 9 = 77.8 g fat per day.",
          },
        ],
        result:
          "Recommended fat intake range: approximately 44 to 78 grams per day.",
      }}
      relatedCalculators={[
        {
          title: "BMI ΓÇö Body Mass Index Calculator",
          url: "/health/bmi-body-mass-index",
          icon: "ΓÜû∩╕Å",
        },
        {
          title: "BMR ΓÇö Basal Metabolic Rate (Mifflin-St Jeor)",
          url: "/health/bmr-mifflin-st-jeor",
          icon: "≡ƒöÑ",
        },
        {
          title: "TDEE ΓÇö Total Daily Energy Expenditure Calculator",
          url: "/health/tdee-daily-energy-expenditure",
          icon: "≡ƒöÑ",
        },
        {
          title: "Body Fat % (US Navy / 3-sites)",
          url: "/health/body-fat-us-navy-3-sites",
          icon: "≡ƒÆº",
        },
        {
          title: "Ideal Weight Range (Hamwi/Devine/Miller)",
          url: "/health/ideal-weight-range-hamwi-devine-miller",
          icon: "≡ƒÑù",
        },
        {
          title: "Waist-to-Height Ratio Checker",
          url: "/health/waist-to-height-ratio",
          icon: "≡ƒÿ┤",
        },
      ]}
      onThisPage={[
        { id: "what-is", label: "What is Fat Intake Range (AMDR)?" },
        { id: "how-to-use", label: "How to Use This Calculator" },
        { id: "faq", label: "Frequently Asked Questions" },
        { id: "references", label: "Trusted References" },
      ]}
      showTopBanner
      showSidebar
      showBottomBanner
    />
  );
}

import { useState, useMemo } from "react";
import CalculatorVerticalLayout from '@/components/templates/CalculatorVerticalLayout';
import { Card, CardContent } from "@/components/ui/card";
import { Label } from "@/components/ui/label";
import { Input } from "@/components/ui/input";
import { Button } from "@/components/ui/button";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Activity, Calculator, RotateCcw } from "lucide-react";
import useFaqJsonLd from "@/hooks/useFaqJsonLd";

export default function TdeeGestationAdjustedCalculator() {
  // 1. STATE (Imperial Default)
  const [unit, setUnit] = useState("imperial");
  const [inputs, setInputs] = useState({
    weight: "", // lbs or kg
    heightFeet: "", // feet (imperial only)
    heightInches: "", // inches (imperial only)
    heightCm: "", // cm (metric only)
    age: "", // years
    activityLevel: "sedentary",
    trimester: "2", // 1, 2, or 3
  });

  // Activity multipliers based on common TDEE multipliers
  const activityMultipliers: Record<string, number> = {
    sedentary: 1.2,
    light: 1.375,
    moderate: 1.55,
    active: 1.725,
    veryActive: 1.9,
  };

  // Gestational calorie increase per trimester (approximate)
  // Based on Health Canada and ACOG guidelines:
  // 1st trimester: no increase or minimal (~0 kcal)
  // 2nd trimester: +340 kcal/day
  // 3rd trimester: +452 kcal/day
  const trimesterCalories: Record<string, number> = {
    "1": 0,
    "2": 340,
    "3": 452,
  };

  // 2. LOGIC
  const results = useMemo(() => {
    // Validate inputs
    const weightNum = parseFloat(inputs.weight);
    const ageNum = parseInt(inputs.age);
    let heightCmNum = 0;

    if (
      !weightNum ||
      weightNum <= 0 ||
      !ageNum ||
      ageNum < 14 || // pregnancy usually from teens up
      ageNum > 50
    ) {
      return { value: 0, label: "Please enter valid weight and age", category: "" };
    }

    if (unit === "imperial") {
      const feetNum = parseInt(inputs.heightFeet);
      const inchesNum = parseInt(inputs.heightInches);
      if (
        !feetNum ||
        feetNum <= 0 ||
        feetNum > 8 ||
        inchesNum === undefined ||
        inchesNum < 0 ||
        inchesNum >= 12
      ) {
        return { value: 0, label: "Please enter valid height", category: "" };
      }
      heightCmNum = (feetNum * 12 + inchesNum) * 2.54;
    } else {
      const cmNum = parseFloat(inputs.heightCm);
      if (!cmNum || cmNum < 100 || cmNum > 250) {
        return { value: 0, label: "Please enter valid height", category: "" };
      }
      heightCmNum = cmNum;
    }

    // Convert weight to kg if imperial
    const weightKg = unit === "imperial" ? weightNum * 0.45359237 : weightNum;

    // Mifflin-St Jeor Equation for BMR (women)
    // BMR = (10 ├ù weight in kg) + (6.25 ├ù height in cm) ΓêÆ (5 ├ù age in years) ΓêÆ 161
    const bmr = 10 * weightKg + 6.25 * heightCmNum - 5 * ageNum - 161;

    // Activity multiplier
    const activityMultiplier = activityMultipliers[inputs.activityLevel] || 1.2;

    // Base TDEE before pregnancy adjustment
    const baseTDEE = bmr * activityMultiplier;

    // Add gestational calorie increase based on trimester
    const gestationalIncrease = trimesterCalories[inputs.trimester] || 0;

    // Final Gestational TDEE rounded to nearest kcal
    const gestationalTDEE = Math.round(baseTDEE + gestationalIncrease);

    return {
      value: gestationalTDEE,
      label: "Estimated Gestational TDEE (kcal/day)",
      category: `Trimester ${inputs.trimester}`,
    };
  }, [inputs, unit]);

  // 3. FAQS
  const faqs = [
    {
      question: "What is Gestational TDEE and why is it important?",
      answer:
        "Gestational Total Daily Energy Expenditure (TDEE) estimates the total calories a pregnant person needs daily, accounting for basal metabolism, physical activity, and the additional energy demands of pregnancy. Proper estimation helps ensure adequate nutrition for fetal growth and maternal health, reducing risks of complications such as low birth weight or excessive weight gain.",
    },
    {
      question: "How should I interpret my Gestational TDEE result?",
      answer:
        "The calculated Gestational TDEE represents an estimate of daily calorie needs during pregnancy for your specific trimester, activity level, and body metrics. It guides nutritional intake to support healthy fetal development and maternal well-being. However, individual needs may vary, so consult a healthcare provider for personalized advice.",
    },
    {
      question: "What are the limitations of this calculator?",
      answer:
        "This calculator provides an educational estimate based on population averages and standard formulas. It does not account for individual metabolic differences, pregnancy complications, or multiple gestations (twins, triplets). It should not replace professional medical or nutritional advice.",
    },
    {
      question: "Why does the calorie increase vary by trimester?",
      answer:
        "Energy requirements increase as pregnancy progresses due to fetal growth and maternal tissue development. The first trimester typically requires minimal additional calories, while the second and third trimesters see significant increases to support rapid fetal growth and prepare for lactation.",
    },
  ];
  const faqJsonLd = useFaqJsonLd(faqs);

  // Handlers for inputs
  function handleInputChange(field: string, value: string) {
    setInputs((prev) => ({ ...prev, [field]: value }));
  }

  // Reset inputs to defaults
  function resetInputs() {
    setInputs({
      weight: "",
      heightFeet: "",
      heightInches: "",
      heightCm: "",
      age: "",
      activityLevel: "sedentary",
      trimester: "2",
    });
  }

  const widget = (
    <div className="space-y-6">
      {/* Unit Switcher & Inputs */}
      <div className="space-y-4">
        <div className="flex items-center justify-between">
          <Label className="text-slate-700 dark:text-slate-300">Unit System</Label>
          <Select value={unit} onValueChange={setUnit}>
            <SelectTrigger className="w-[180px]">
              <SelectValue />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="imperial">Imperial (US/Canada)</SelectItem>
              <SelectItem value="metric">Metric (International)</SelectItem>
            </SelectContent>
          </Select>
        </div>

        {/* Weight */}
        <div>
          <Label htmlFor="weight" className="text-slate-700 dark:text-slate-300">
            Weight ({unit === "imperial" ? "lbs" : "kg"})
          </Label>
          <Input
            id="weight"
            type="number"
            min={1}
            max={1000}
            step="any"
            value={inputs.weight}
            onChange={(e) => handleInputChange("weight", e.target.value)}
            placeholder={unit === "imperial" ? "e.g. 150" : "e.g. 68"}
            className="max-w-xs"
          />
        </div>

        {/* Height */}
        {unit === "imperial" ? (
          <div className="flex space-x-4">
            <div className="flex-1">
              <Label htmlFor="heightFeet" className="text-slate-700 dark:text-slate-300">
                Height (feet)
              </Label>
              <Input
                id="heightFeet"
                type="number"
                min={1}
                max={8}
                step={1}
                value={inputs.heightFeet}
                onChange={(e) => handleInputChange("heightFeet", e.target.value)}
                placeholder="5"
              />
            </div>
            <div className="flex-1">
              <Label htmlFor="heightInches" className="text-slate-700 dark:text-slate-300">
                Height (inches)
              </Label>
              <Input
                id="heightInches"
                type="number"
                min={0}
                max={11}
                step={1}
                value={inputs.heightInches}
                onChange={(e) => handleInputChange("heightInches", e.target.value)}
                placeholder="7"
              />
            </div>
          </div>
        ) : (
          <div>
            <Label htmlFor="heightCm" className="text-slate-700 dark:text-slate-300">
              Height (cm)
            </Label>
            <Input
              id="heightCm"
              type="number"
              min={100}
              max={250}
              step="any"
              value={inputs.heightCm}
              onChange={(e) => handleInputChange("heightCm", e.target.value)}
              placeholder="e.g. 170"
              className="max-w-xs"
            />
          </div>
        )}

        {/* Age */}
        <div>
          <Label htmlFor="age" className="text-slate-700 dark:text-slate-300">
            Age (years)
          </Label>
          <Input
            id="age"
            type="number"
            min={14}
            max={50}
            step={1}
            value={inputs.age}
            onChange={(e) => handleInputChange("age", e.target.value)}
            placeholder="e.g. 28"
            className="max-w-xs"
          />
        </div>

        {/* Activity Level */}
        <div>
          <Label htmlFor="activityLevel" className="text-slate-700 dark:text-slate-300">
            Activity Level
          </Label>
          <Select
            id="activityLevel"
            value={inputs.activityLevel}
            onValueChange={(val) => handleInputChange("activityLevel", val)}
          >
            <SelectTrigger className="w-[220px]">
              <SelectValue />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="sedentary">Sedentary (little or no exercise)</SelectItem>
              <SelectItem value="light">Lightly active (light exercise 1-3 days/week)</SelectItem>
              <SelectItem value="moderate">Moderately active (moderate exercise 3-5 days/week)</SelectItem>
              <SelectItem value="active">Active (hard exercise 6-7 days/week)</SelectItem>
              <SelectItem value="veryActive">Very active (very hard exercise & physical job)</SelectItem>
            </SelectContent>
          </Select>
        </div>

        {/* Trimester */}
        <div>
          <Label htmlFor="trimester" className="text-slate-700 dark:text-slate-300">
            Pregnancy Trimester
          </Label>
          <Select
            id="trimester"
            value={inputs.trimester}
            onValueChange={(val) => handleInputChange("trimester", val)}
          >
            <SelectTrigger className="w-[180px]">
              <SelectValue />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="1">1st Trimester (Weeks 1-12)</SelectItem>
              <SelectItem value="2">2nd Trimester (Weeks 13-26)</SelectItem>
              <SelectItem value="3">3rd Trimester (Weeks 27-40)</SelectItem>
            </SelectContent>
          </Select>
        </div>
      </div>

      {/* Buttons */}
      <div className="flex flex-col sm:flex-row gap-3 pt-4">
        <Button
          className="flex-1 h-11 bg-blue-600 hover:bg-blue-700 text-white font-semibold shadow-md"
          onClick={() => {}}
          type="button"
        >
          <Calculator className="mr-2 h-4 w-4" /> Calculate
        </Button>
        <Button
          variant="outline"
          onClick={resetInputs}
          className="flex-1 h-11 hover:bg-slate-100 dark:hover:bg-slate-800"
          type="button"
        >
          <RotateCcw className="mr-2 h-4 w-4" /> Reset
        </Button>
      </div>

      {/* Results (High Contrast for Dark Mode) */}
      {results.value !== 0 && (
        <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4">
          <Card className="bg-gradient-to-br from-blue-50 to-indigo-100 dark:from-slate-900 dark:to-slate-950 border-blue-200 shadow-lg">
            <CardContent className="p-8 text-center">
              <p className="text-sm font-bold text-blue-900 dark:text-blue-100 mb-3 uppercase tracking-wider">
                Your Result
              </p>
              <p className="text-5xl font-extrabold text-blue-900 dark:text-white">{results.value}</p>
              <p className="text-slate-600 dark:text-slate-300 mt-2 font-medium">{results.label}</p>
              {results.category && (
                <div className="mt-4 inline-flex items-center px-3 py-1 rounded-full bg-white/50 dark:bg-slate-800 border border-blue-200 dark:border-slate-700 text-blue-800 dark:text-blue-300 text-sm font-bold">
                  {results.category}
                </div>
              )}
            </CardContent>
          </Card>
        </div>
      )}
    </div>
  );

  const editorial = (
    <div className="space-y-12">
      {/* MANDATORY "WHAT IS" SECTION */}
      <section id="what-is" className="scroll-mt-32">
        <h2 className="text-3xl font-bold mb-4 text-slate-900 dark:text-slate-100">
          What is the Gestational TDEE (educational)?
        </h2>
        <p className="text-slate-700 dark:text-slate-300 leading-relaxed mb-4">
          Gestational Total Daily Energy Expenditure (TDEE) refers to the total number of calories a pregnant person requires each day to maintain their own bodily functions, support physical activity, and provide the additional energy necessary for fetal growth and development. Unlike standard TDEE calculations, gestational TDEE accounts for the increased metabolic demands of pregnancy, which vary by trimester as the fetus grows and maternal tissues develop.
        </p>
        <p className="text-slate-700 dark:text-slate-300 leading-relaxed mb-4">
          During pregnancy, energy needs increase progressively, especially in the second and third trimesters. This increase supports the formation of the placenta, amniotic fluid, maternal fat stores, and the growing fetus. Accurately estimating gestational TDEE is crucial for ensuring adequate maternal nutrition, which can influence pregnancy outcomes such as birth weight, gestational age, and maternal health.
        </p>
        <p className="text-slate-700 dark:text-slate-300 leading-relaxed mb-4">
          This calculator uses the Mifflin-St Jeor equation to estimate basal metabolic rate (BMR), adjusts for physical activity level, and then adds trimester-specific calorie increments recommended by leading health authorities. It is designed as an educational tool to help pregnant individuals and healthcare providers understand energy needs during pregnancy but should not replace personalized medical advice.
        </p>
        <p className="text-slate-700 dark:text-slate-300 leading-relaxed">
          Understanding gestational TDEE can help guide dietary planning to meet increased nutritional demands, prevent excessive or inadequate weight gain, and promote optimal health for both mother and baby. It is important to consider individual factors such as pre-pregnancy weight, metabolic health, and activity levels when interpreting results.
        </p>
      </section>

      <section id="how-to-use" className="scroll-mt-32">
        <h2 className="text-3xl font-bold mb-4 text-slate-900 dark:text-slate-100">How to Use This Calculator</h2>
        <p className="text-slate-700 dark:text-slate-300 leading-relaxed mb-4">
          To estimate your Gestational TDEE, enter your current weight, height, age, activity level, and select your current pregnancy trimester. The calculator will use these inputs to estimate your daily calorie needs, including the additional energy required for your pregnancy stage.
        </p>
        <ul className="list-disc pl-5 space-y-2 text-slate-700 dark:text-slate-300">
          <li>
            <strong>Weight:</strong> Enter your current body weight. Use pounds if you selected Imperial units or kilograms for Metric.
          </li>
          <li>
            <strong>Height:</strong> Enter your height. For Imperial units, input feet and inches separately; for Metric, enter centimeters.
          </li>
          <li>
            <strong>Age:</strong> Enter your age in years. This helps adjust basal metabolic rate calculations.
          </li>
          <li>
            <strong>Activity Level:</strong> Select the option that best describes your typical daily physical activity, from sedentary to very active.
          </li>
          <li>
            <strong>Trimester:</strong> Choose your current pregnancy trimester to apply the appropriate calorie increase.
          </li>
        </ul>
        <p className="text-slate-700 dark:text-slate-300 leading-relaxed mt-4">
          After entering all information, click "Calculate" to see your estimated Gestational TDEE. Use this number as a guide for daily calorie intake to support a healthy pregnancy.
        </p>
      </section>

      <section id="faq" className="scroll-mt-32">
        <h2 className="text-3xl font-bold mb-4 text-slate-900 dark:text-slate-100">Frequently Asked Questions</h2>
        <ul className="space-y-6">
          {faqs.map((item, i) => (
            <li key={i} className="border-b border-slate-200 dark:border-slate-800 pb-4 last:border-0">
              <h3 className="font-bold text-xl text-slate-900 dark:text-slate-100 mb-2">{item.question}</h3>
              <p className="text-slate-600 dark:text-slate-400 leading-relaxed">{item.answer}</p>
            </li>
          ))}
        </ul>
      </section>

      <section id="references" className="scroll-mt-32">
        <h2 className="text-3xl font-bold mb-4 text-slate-900 dark:text-slate-100">Trusted References</h2>
        <ul className="space-y-4">
          <li className="block">
            <a
              href="https://www.acog.org/womens-health/faqs/nutrition-during-pregnancy"
              target="_blank"
              rel="noopener noreferrer"
              className="text-blue-600 font-bold hover:underline text-lg"
            >
              1. American College of Obstetricians and Gynecologists (ACOG) - Nutrition During Pregnancy
            </a>
            <p className="text-slate-500 text-sm mt-1">
              Authoritative guidelines on nutritional needs and calorie requirements during pregnancy.
            </p>
          </li>
          <li className="block">
            <a
              href="https://www.canada.ca/en/health-canada/services/food-nutrition/healthy-eating/healthy-pregnancy.html"
              target="_blank"
              rel="noopener noreferrer"
              className="text-blue-600 font-bold hover:underline text-lg"
            >
              2. Health Canada - Healthy Pregnancy Nutrition
            </a>
            <p className="text-slate-500 text-sm mt-1">
              Canadian government resource detailing dietary recommendations and energy needs for pregnant individuals.
            </p>
          </li>
          <li className="block">
            <a
              href="https://www.nal.usda.gov/fnic/dietary-reference-intakes"
              target="_blank"
              rel="noopener noreferrer"
              className="text-blue-600 font-bold hover:underline text-lg"
            >
              3. National Academies of Sciences, Engineering, and Medicine - Dietary Reference Intakes
            </a>
            <p className="text-slate-500 text-sm mt-1">
              Comprehensive nutrient and energy intake recommendations including pregnancy-specific adjustments.
            </p>
          </li>
          <li className="block">
            <a
              href="https://pubmed.ncbi.nlm.nih.gov/24529832/"
              target="_blank"
              rel="noopener noreferrer"
              className="text-blue-600 font-bold hover:underline text-lg"
            >
              4. Institute of Medicine (US) - Weight Gain During Pregnancy: Reexamining the Guidelines (2009)
            </a>
            <p className="text-slate-500 text-sm mt-1">
              Evidence-based guidelines on energy needs and weight gain patterns during pregnancy.
            </p>
          </li>
        </ul>
      </section>
    </div>
  );

  return (
    <CalculatorVerticalLayout
      title="Gestational TDEE (educational)"
      description="Estimate energy needs during pregnancy. Calculate adjusted TDEE to ensure adequate nutrition for fetal development and maternal health."
      widget={widget}
      editorial={editorial}
      jsonLd={faqJsonLd}
      formula={{
        title: "The Math Formula",
        formula:
          "Gestational TDEE = (BMR ├ù Activity Factor) + Trimester Calorie Increase",
        variables: [
          { symbol: "BMR", description: "Basal Metabolic Rate calculated by Mifflin-St Jeor equation" },
          { symbol: "Activity Factor", description: "Multiplier based on physical activity level" },
          { symbol: "Trimester Calorie Increase", description: "Additional calories required per trimester (0, 340, or 452 kcal)" },
        ],
      }}
      example={{
        title: "Real-World Example",
        scenario:
          "A 28-year-old pregnant woman in her 2nd trimester weighs 150 lbs, is 5 ft 7 in tall, and has a moderately active lifestyle.",
        steps: [
          {
            label: "Step 1",
            explanation:
              "Calculate BMR using Mifflin-St Jeor: BMR = (10 ├ù 68.04 kg) + (6.25 ├ù 170 cm) ΓêÆ (5 ├ù 28) ΓêÆ 161 = 1460 kcal/day",
          },
          {
            label: "Step 2",
            explanation:
              "Multiply BMR by activity factor for moderate activity (1.55): 1460 ├ù 1.55 = 2263 kcal/day",
          },
          {
            label: "Step 3",
            explanation:
              "Add 2nd trimester calorie increase (340 kcal): 2263 + 340 = 2603 kcal/day",
          },
        ],
        result: "Estimated Gestational TDEE is approximately 2603 kcal/day.",
      }}
      relatedCalculators={[
        { title: "BMI ΓÇö Body Mass Index Calculator", url: "/health/bmi-body-mass-index", icon: "ΓÜû∩╕Å" },
        { title: "BMR ΓÇö Basal Metabolic Rate (Mifflin-St Jeor)", url: "/health/bmr-mifflin-st-jeor", icon: "≡ƒöÑ" },
        { title: "TDEE ΓÇö Total Daily Energy Expenditure Calculator", url: "/health/tdee-daily-energy-expenditure", icon: "≡ƒöÑ" },
        { title: "Body Fat % (US Navy / 3-sites)", url: "/health/body-fat-us-navy-3-sites", icon: "≡ƒÆº" },
        { title: "Ideal Weight Range (Hamwi/Devine/Miller)", url: "/health/ideal-weight-range-hamwi-devine-miller", icon: "≡ƒÑù" },
        { title: "Waist-to-Height Ratio Checker", url: "/health/waist-to-height-ratio", icon: "≡ƒÿ┤" },
      ]}
      onThisPage={[
        { id: "what-is", label: "What is Gestational TDEE (educational)?" },
        { id: "how-to-use", label: "How to Use This Calculator" },
        { id: "faq", label: "Frequently Asked Questions" },
        { id: "references", label: "Trusted References" },
      ]}
      showTopBanner
      showSidebar
      showBottomBanner
    />
  );
}

import { useState, useMemo, useCallback } from "react";
import CalculatorVerticalLayout from '@/components/templates/CalculatorVerticalLayout';
import { Card, CardContent } from "@/components/ui/card";
import { Label } from "@/components/ui/label";
import { Input } from "@/components/ui/input";
import { Button } from "@/components/ui/button";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
// ΓÜá∩╕Å FULL ICON IMPORT
import { Home, Heart, Utensils, Leaf, Calendar, DollarSign, Droplets, Activity, Moon, Sun, Users, Paintbrush, Wrench, Info, RotateCcw, AlertTriangle, FlaskConical, Scale, Waves, Zap, BookOpen, ExternalLink } from "lucide-react";
import useFaqJsonLd from "@/hooks/useFaqJsonLd";

export default function EventCapacityCalculator() {
  const [inputs, setInputs] = useState({
    area: "",
    layout: "",
    standingPercent: "",
  });
  const handleInputChange = useCallback((n, v) => setInputs(p => ({ ...p, [n]: v })), []);

  /**
   * Calculation logic:
   * 1. Base capacity = total area (sq ft) / space per person (sq ft)
   * 2. Space per person depends on seating layout:
   *    - Standing: 5 sq ft per person (typical for cocktail events)
   *    - Theater: 7 sq ft per person (rows of chairs)
   *    - Banquet: 12 sq ft per person (tables + chairs)
   *    - Classroom: 15 sq ft per person (tables + chairs with writing space)
   * 3. Optionally, user can specify % standing guests to adjust space needs.
   */

  const seatingSpaceMap = {
    standing: 5,
    theater: 7,
    banquet: 12,
    classroom: 15,
  };

  const results = useMemo(() => {
    const areaNum = parseFloat(inputs.area);
    const layout = inputs.layout;
    const standingPercentNum = parseFloat(inputs.standingPercent);

    if (!areaNum || areaNum <= 0) {
      return {
        value: null,
        label: "",
        subtext: "Please enter a valid venue area in square feet.",
        warning: null,
        formulaUsed: "",
      };
    }
    if (!layout) {
      return {
        value: null,
        label: "",
        subtext: "Please select a seating layout.",
        warning: null,
        formulaUsed: "",
      };
    }

    // Calculate capacity
    // If standingPercent is provided and layout is not standing, calculate weighted average space per person
    let spacePerPerson = seatingSpaceMap[layout];
    let warning = null;

    if (layout !== "standing" && standingPercentNum && standingPercentNum > 0 && standingPercentNum <= 100) {
      // Weighted average space per person:
      // standing guests take 5 sq ft, seated guests take layout sq ft
      const seatedPercent = 100 - standingPercentNum;
      spacePerPerson =
        (standingPercentNum * seatingSpaceMap.standing + seatedPercent * seatingSpaceMap[layout]) / 100;
    } else if (layout === "standing" && standingPercentNum) {
      warning = "Standing layout selected; standing guest percentage input is ignored.";
    }

    // Safety margin: reduce capacity by 10% to allow for aisles, emergency exits, and comfort
    const rawCapacity = areaNum / spacePerPerson;
    const safeCapacity = Math.floor(rawCapacity * 0.9);

    if (safeCapacity < 1) {
      warning = "Venue area too small for any guests with the selected layout.";
    }

    return {
      value: safeCapacity > 0 ? safeCapacity.toString() : "0",
      label: "Maximum Safe Capacity",
      subtext: `Based on ${areaNum} sq ft and "${layout.charAt(0).toUpperCase() + layout.slice(1)}" layout.`,
      warning,
      formulaUsed: `Capacity = (Area ├╖ Space per Person) ├ù 0.9 (safety margin). Space per Person adjusted for standing guests if applicable.`,
    };
  }, [inputs]);

  const faqs = [
    {
      question: "What is the recommended space per person for different event layouts?",
      answer:
        "The space per person varies by event type: standing events typically require about 5 sq ft per person, theater seating about 7 sq ft, banquet seating about 12 sq ft, and classroom setups about 15 sq ft. These values account for seating, tables, and circulation space to ensure comfort and safety.",
    },
    {
      question: "Why is there a 10% safety margin applied in the calculation?",
      answer:
        "The 10% safety margin accounts for aisles, emergency exits, and general comfort, ensuring that the venue does not become overcrowded. This margin aligns with fire safety codes and best practices recommended by safety authorities.",
    },
    {
      question: "Can this calculator be used for outdoor venues?",
      answer:
        "Yes, but outdoor venues often have different spacing requirements due to open air and layout flexibility. It's recommended to consult local regulations and consider additional space for pathways and amenities when planning outdoor events.",
    },
  ];
  const faqJsonLd = useFaqJsonLd(faqs);

  const widget = (
    <div className="space-y-6">
      <Card>
        <CardContent>
          <div className="space-y-4">
            <div>
              <Label htmlFor="area" className="flex items-center gap-2">
                <Home className="w-5 h-5 text-blue-600" /> Venue Area (sq ft)
              </Label>
              <Input
                id="area"
                type="number"
                min={0}
                step={1}
                placeholder="e.g., 1000"
                value={inputs.area}
                onChange={(e) => handleInputChange("area", e.target.value)}
              />
            </div>

            <div>
              <Label htmlFor="layout" className="flex items-center gap-2">
                <Users className="w-5 h-5 text-blue-600" /> Seating Layout
              </Label>
              <Select
                value={inputs.layout}
                onValueChange={(v) => handleInputChange("layout", v)}
                id="layout"
              >
                <SelectTrigger>
                  <SelectValue placeholder="Select layout" />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="standing">
                    Standing (Cocktail) <Zap className="inline w-4 h-4 ml-1 text-yellow-500" />
                  </SelectItem>
                  <SelectItem value="theater">
                    Theater (Rows of Chairs) <Activity className="inline w-4 h-4 ml-1 text-green-600" />
                  </SelectItem>
                  <SelectItem value="banquet">
                    Banquet (Tables & Chairs) <Utensils className="inline w-4 h-4 ml-1 text-red-600" />
                  </SelectItem>
                  <SelectItem value="classroom">
                    Classroom (Tables & Chairs) <BookOpen className="inline w-4 h-4 ml-1 text-indigo-600" />
                  </SelectItem>
                </SelectContent>
              </Select>
            </div>

            <div>
              <Label htmlFor="standingPercent" className="flex items-center gap-2">
                <Activity className="w-5 h-5 text-blue-600" /> Percentage of Standing Guests (optional)
              </Label>
              <Input
                id="standingPercent"
                type="number"
                min={0}
                max={100}
                step={1}
                placeholder="e.g., 20"
                value={inputs.standingPercent}
                onChange={(e) => handleInputChange("standingPercent", e.target.value)}
                disabled={inputs.layout === "standing"}
              />
              {inputs.layout === "standing" && (
                <p className="text-sm text-slate-500 mt-1 italic">
                  Standing layout selected; this input is disabled.
                </p>
              )}
            </div>
          </div>
        </CardContent>
      </Card>

      <div className="flex flex-col sm:flex-row gap-3 pt-4">
        <Button
          onClick={() => {
            // No extra action needed, calculation is reactive
          }}
          className="flex-1 h-11 bg-blue-600 hover:bg-blue-700 text-white shadow-md"
          aria-label="Calculate event capacity"
        >
          <Home className="mr-2 h-4 w-4" /> Calculate
        </Button>
        <Button
          variant="outline"
          onClick={() => setInputs({ area: "", layout: "", standingPercent: "" })}
          className="flex-1 h-11"
          aria-label="Reset inputs"
        >
