    steps: [
      {
        label: "1",
        explanation:
          "Calculate weight factor: Ideal weight 0.22 lbs, actual 0.18 lbs ΓåÆ underweight, weight factor Γëê 9.1",
      },
      {
        label: "2",
        explanation:
          "Age factor: 4 months < 6 months ΓåÆ 15 points added for immature reproductive system",
      },
      {
        label: "3",
        explanation:
          "Egg-laying frequency factor: (5/7)*30 Γëê 21.4 points for frequent laying",
      },
      {
        label: "4",
        explanation:
          "Nutrition deficit factor: (10 - 6)*5 = 20 points for suboptimal nutrition",
      },
    ],
    result:
      "Total risk score = 9.1 + 15 + 21.4 + 20 = 65.5%, indicating moderate to high risk of egg binding.",
  };

  // 6. WIDGET (INPUTS + RESULTS)
  const widget = (
    <div className="space-y-6">
      <div className="space-y-4">
        <div className="flex items-center justify-between">
          <Label className="text-slate-700 dark:text-slate-300">Unit System</Label>
          <Select value={unit} onValueChange={setUnit}>
            <SelectTrigger className="w-[180px]">
              <SelectValue />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="lb">lb</SelectItem>
              <SelectItem value="kg">kg</SelectItem>
            </SelectContent>
          </Select>
