          },
        ],
      }}
      example={{
        title: "Case Study",
        scenario:
          "A 1100 lb horse ingests approximately 0.5 lbs of Ragwort in pasture.",
        steps: [
          {
            label: "1",
            explanation:
              "Convert horse weight to kg: 1100 lb ├╖ 2.20462 = 499 kg.",
          },
          {
