      editorial={editorial}
      jsonLd={faqJsonLd}
      // ΓÜá∩╕Å CLEAN FORMULA: ONLY ONE LINE. NO COMPLICATED MATH DUMPS.
      formula={{
        title: "Scientific Formula",
        formula: "Dose (mg) = Body Weight (kg) ├ù Dose (mg/kg)",
