  });

  const handleInputChange = useCallback((name, value) => {
    setInputs((prev) => ({ ...prev, [name]: value }));
  }, []);

  // Constants
  const PLANCK_CONSTANT = 6.62607015e-34; // J┬╖s

  // Frequency unit multipliers to Hz
  const frequencyUnitMultipliers = {
    Hz: 1,
    kHz: 1e3,
    MHz: 1e6,
    GHz: 1e9,
    THz: 1e12,
  };

  const results = useMemo(() => {
    const freqRaw = inputs.frequency.trim();
    const freqNum = Number(freqRaw);
    const unit = inputs.unit;

    if (!freqRaw) {
      return {
        value: "Waiting...",
        label: "",
        subtext: "",
        warning: null,
        formulaUsed: "E = h ├ù f",
      };
    }

    if (isNaN(freqNum)) {
      return {
        value: "Invalid input",
        label: "",
        subtext: "",
        warning: "Frequency must be a valid number.",
        formulaUsed: "E = h ├ù f",
      };
    }

    if (freqNum < 0) {
      return {
        value: "Invalid input",
        label: "",
        subtext: "",
        warning: "Frequency cannot be negative. Please enter a value &ge; 0.",
        formulaUsed: "E = h ├ù f",
      };
    }

    const freqHz = freqNum * (frequencyUnitMultipliers[unit] ?? 1);

    // Calculate photon energy: E = h * f
    const energyJoules = PLANCK_CONSTANT * freqHz;

    // Format energy in scientific notation with 4 decimals
    const energyFormatted = energyJoules.toExponential(4) + " Joules";

    // Provide subtext with frequency in Hz
    const freqFormatted =
      freqHz >= 1e9
        ? (freqHz / 1e9).toFixed(4) + " ├ù 10Γü╣ Hz"
        : freqHz >= 1e6
        ? (freqHz / 1e6).toFixed(4) + " ├ù 10Γü╢ Hz"
        : freqHz >= 1e3
        ? (freqHz / 1e3).toFixed(4) + " ├ù 10┬│ Hz"
        : freqHz.toFixed(4) + " Hz";

    return {
      value: energyFormatted,
      label: "Photon Energy",
      subtext: `Calculated using frequency = ${freqFormatted}`,
      warning: null,
      formulaUsed: "E = h ├ù f",
    };
  }, [inputs]);

  const faqs = [
    {
      question: "What is photon energy and why is it important?",
      answer:
        "Photon energy is the amount of energy carried by a single photon, the fundamental particle of light. It is directly proportional to the frequency of the photon and is crucial in understanding phenomena in quantum physics, such as the photoelectric effect and atomic transitions.",
    },
    {
      question: "How do I convert frequency units for this calculator?",
      answer:
        "You can enter frequency values in Hertz (Hz), kilohertz (kHz), megahertz (MHz), gigahertz (GHz), or terahertz (THz). The calculator automatically converts these units to Hertz for accurate energy calculation.",
    },
    {
      question: "Can the photon energy be zero or negative?",
      answer:
        "Photon energy cannot be negative because frequency cannot be negative. If frequency is zero, photon energy is zero, meaning no photon energy is present. This calculator warns if negative frequencies are entered.",
    },
  ];
  const faqJsonLd = useFaqJsonLd(faqs);

  const widget = (
    <div className="space-y-6">
      {/* Inputs */}
      <div>
        <Label htmlFor="frequency" className="flex items-center gap-2 font-semibold text-slate-700 dark:text-slate-300 mb-1">
          <Zap className="w-5 h-5 text-yellow-600" />
          Frequency
        </Label>
        <div className="flex gap-2">
          <Input
            id="frequency"
            type="text"
            placeholder="Enter frequency"
            value={inputs.frequency}
            onChange={(e) => handleInputChange("frequency", e.target.value)}
            aria-describedby="frequency-desc"
          />
          <Select
            value={inputs.unit}
            onValueChange={(value) => handleInputChange("unit", value)}
            aria-label="Select frequency unit"
          >
            <SelectTrigger className="w-24">
              <SelectValue />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="Hz">Hz</SelectItem>
              <SelectItem value="kHz">kHz</SelectItem>
              <SelectItem value="MHz">MHz</SelectItem>
              <SelectItem value="GHz">GHz</SelectItem>
              <SelectItem value="THz">THz</SelectItem>
            </SelectContent>
          </Select>
        </div>
        <p id="frequency-desc" className="text-sm text-slate-500 dark:text-slate-400 mt-1">
          Enter the frequency of the photon. Frequency must be a number &ge; 0.
        </p>
      </div>

      {/* Buttons */}
      <div className="flex flex-col sm:flex-row gap-3 pt-4">
        <Button
          className="flex-1 h-11 bg-blue-600 hover:bg-blue-700 text-white font-semibold shadow-md"
          onClick={() => {
            // No explicit calculation needed on click since useMemo updates automatically
          }}
          aria-label="Calculate photon energy"
        >
          <Atom className="mr-2 h-4 w-4" /> Calculate
        </Button>
        <Button
          variant="outline"
          onClick={() => setInputs({ frequency: "", unit: "Hz" })}
          className="flex-1 h-11 hover:bg-slate-100 dark:hover:bg-slate-800"
          aria-label="Reset inputs"
        >
          <RotateCcw className="mr-2 h-4 w-4" /> Reset
        </Button>
      </div>

      {/* Results */}
      {results.value !== "Waiting..." && (
        <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4" role="region" aria-live="polite" aria-atomic="true">
          <Card className="bg-gradient-to-br from-blue-50 to-indigo-100 dark:from-slate-900 dark:to-slate-950 border-blue-200 shadow-lg">
            <CardContent className="p-8 text-center">
              <p className="text-sm font-bold text-blue-900 dark:text-blue-100 mb-3 uppercase tracking-wider">
                {results.formulaUsed || "Calculated Result"}
              </p>
              <p className="text-5xl font-extrabold text-blue-900 dark:text-white">{results.value}</p>
              <p className="text-slate-600 dark:text-slate-300 mt-2 font-medium">{results.label}</p>
              {results.subtext && <p className="text-sm text-slate-500 mt-2">{results.subtext}</p>}
              {results.warning && (
                <div className="mt-4 p-3 bg-red-50 dark:bg-red-950 border border-red-200 rounded-lg flex items-start gap-3 text-left">
                  <AlertTriangle className="w-5 h-5 text-red-600 shrink-0 mt-0.5" />
                  <p className="text-sm text-red-800 dark:text-red-200">{results.warning}</p>
                </div>
              )}
            </CardContent>
          </Card>
        </div>
      )}
    </div>
  );

  const editorial = (
    <div className="space-y-12">
      <section id="what-is" className="scroll-mt-32">
        <h2 className="text-3xl font-bold mb-4 text-slate-900 dark:text-slate-100">Understanding Photon Energy Calculator</h2>
        <p className="text-slate-700 dark:text-slate-300 leading-relaxed mb-4">
          Photons are elementary particles representing quanta of light and other electromagnetic radiation. Each photon carries energy proportional to its frequency. The Photon Energy Calculator helps you determine the energy of a photon by inputting its frequency. This is essential in quantum physics, where energy quantization explains phenomena like the photoelectric effect and atomic emission spectra.
        </p>
        <p className="text-slate-700 dark:text-slate-300 leading-relaxed mb-4">
          Frequency is the number of oscillations or waves per second, measured in Hertz (Hz). Higher frequency photons carry more energy. For example, ultraviolet light photons have higher frequencies and energies than visible light photons. Understanding photon energy is fundamental in fields such as spectroscopy, photonics, and quantum computing.
        </p>
        <p className="text-slate-700 dark:text-slate-300 leading-relaxed">
          Use this calculator by entering the frequency of the photon in various units (Hz, kHz, MHz, GHz, THz). The calculator converts the frequency to Hertz and computes the energy using Planck's constant. Remember, frequency must be a non-negative number, as negative frequencies are physically meaningless.
        </p>
      </section>

      <section id="formula" className="scroll-mt-32">
        <h2 className="text-3xl font-bold mb-4 text-slate-900 dark:text-slate-100">Formula & Variables</h2>
        <pre className="mt-4 p-4 bg-slate-100 dark:bg-slate-800 rounded-lg overflow-x-auto font-mono text-slate-800 dark:text-slate-200">
{`E = h ├ù f

Where:
E = Photon energy (Joules)
h = Planck's constant (6.62607015 ├ù 10Γü╗┬│Γü┤ J┬╖s)
f = Frequency of the photon (Hertz, Hz)

Note: Frequency must be &ge; 0.`}
        </pre>
      </section>

      <section id="faq" className="scroll-mt-32">
        <h2 className="text-3xl font-bold mb-4 text-slate-900 dark:text-slate-100">Frequently Asked Questions</h2>
        <ul className="space-y-6">
          {faqs.map((item, i) => (
            <li key={i} className="border-b border-slate-200 dark:border-slate-800 pb-4 last:border-0">
              <h3 className="font-bold text-xl text-slate-900 dark:text-slate-100 mb-2">{item.question}</h3>
              <p className="text-slate-600 dark:text-slate-400 leading-relaxed">{item.answer}</p>
            </li>
          ))}
        </ul>
      </section>

      <section id="references" className="scroll-mt-32">
        <h2 className="text-3xl font-bold mb-4 text-slate-900 dark:text-slate-100">
          References & Additional Resources
        </h2>
        <ul className="list-disc pl-5 space-y-4 text-slate-700 dark:text-slate-300 leading-relaxed">

          <li>
            <a href="https://en.wikipedia.org/wiki/Special:Search?search=Photon%20Energy" target="_blank" rel="noopener noreferrer" className="text-blue-600 dark:text-blue-400 hover:underline font-semibold">
              Photon Energy - Wikipedia
            </a>
            <p className="text-slate-600 dark:text-slate-400 mt-1">
              A comprehensive encyclopedia article providing an in-depth overview of Photon Energy, including historical context, mathematical derivations, and key applications.
            </p>
          </li>
          <li>
            <a href="https://www.khanacademy.org/search?page_search_query=Photon%20Energy" target="_blank" rel="noopener noreferrer" className="text-blue-600 dark:text-blue-400 hover:underline font-semibold">
              Photon Energy - Khan Academy
            </a>
            <p className="text-slate-600 dark:text-slate-400 mt-1">
              Watch free educational video tutorials and complete interactive practice exercises on Photon Energy at Khan Academy, perfect for visual learners.
            </p>
          </li>
          <li>
            <a href="https://www.physicsclassroom.com/search?q=Photon%20Energy" target="_blank" rel="noopener noreferrer" className="text-blue-600 dark:text-blue-400 hover:underline font-semibold">
              Photon Energy - The Physics Classroom
            </a>
            <p className="text-slate-600 dark:text-slate-400 mt-1">
              Explore student-friendly tutorials, interactives, and concept builders related to Photon Energy designed to improve understanding of physics principles.
            </p>
          </li>
          <li>
            <a href="http://hyperphysics.phy-astr.gsu.edu/hbase/hph.html" target="_blank" rel="noopener noreferrer" className="text-blue-600 dark:text-blue-400 hover:underline font-semibold">
              Photon Energy - HyperPhysics
            </a>
            <p className="text-slate-600 dark:text-slate-400 mt-1">
              Navigate the HyperPhysics concept map to find concise summaries and calculation examples for Photon Energy.
            </p>
          </li>
        </ul>
      </section>
    </div>
  );

  return (
    <CalculatorVerticalLayout
      title="Photon Energy Calculator"
      description="Calculate the energy of a photon. Use Planck's constant and frequency (E=hf) to solve quantum physics problems."
      widget={widget}
      editorial={editorial}
      jsonLd={faqJsonLd}
      formula={{
        title: "Scientific Formula",
        formula: "E = h ├ù f",
        variables: [
          { symbol: "E", description: "Photon energy in Joules (J)" },
          { symbol: "h", description: "Planck's constant (6.62607015 ├ù 10Γü╗┬│Γü┤ J┬╖s)" },
          { symbol: "f", description: "Frequency of the photon in Hertz (Hz)" },
        ],
      }}
      example={{
        title: "Example",
        scenario:
          "Calculate the energy of a photon with a frequency of 5.0 ├ù 10┬╣Γü┤ Hz (visible light).",
        steps: [
          {
            label: "1",
            explanation:
              "Identify the frequency: f = 5.0 ├ù 10┬╣Γü┤ Hz.",
          },
          {
            label: "2",
            explanation:
              "Use Planck's constant: h = 6.62607015 ├ù 10Γü╗┬│Γü┤ J┬╖s.",
          },
          {
            label: "3",
            explanation:
              "Calculate energy: E = h ├ù f = 6.62607015 ├ù 10Γü╗┬│Γü┤ ├ù 5.0 ├ù 10┬╣Γü┤ = 3.313 ├ù 10Γü╗┬╣Γü╣ Joules.",
          },
        ],
        result: "Photon energy is approximately 3.313 ├ù 10Γü╗┬╣Γü╣ Joules.",
      }}
      // USE THIS VARIABLE EXACTLY - NO MANUAL EDITS
      relatedCalculators={[
        { title: "Escape Velocity Calculator", url: "/science/escape-velocity-calculator", icon: "≡ƒº¬" },
        { title: "Ideal Gas Law Calculator", url: "/science/ideal-gas-law-pv-nrt", icon: "≡ƒº¬" },
        { title: "Specific Heat Calculator", url: "/science/specific-heat-q-mc-delta-t", icon: "≡ƒöÑ" },
        { title: "Gravity on Other Planets Calculator", url: "/science/gravity-on-other-planets-calculator", icon: "≡ƒ¬É" },
        { title: "Molar Mass Calculator", url: "/science/molar-mass-calculator", icon: "≡ƒº¬" },
        { title: "Heat Transfer (Conduction) Calculator", url: "/science/heat-transfer-conduction", icon: "≡ƒöÑ" },
      ]}
      onThisPage={[
        { id: "what-is", label: "Understanding" },
        { id: "formula", label: "Formula" },
        { id: "faq", label: "FAQ" },
        { id: "references", label: "References & Resources" }
      ]}
      showTopBanner
      showSidebar
      showBottomBanner
    />
  );
}

import { useState, useMemo, useCallback } from "react";
import CalculatorVerticalLayout from '@/components/templates/CalculatorVerticalLayout';
import { Card, CardContent } from "@/components/ui/card";
import { Label } from "@/components/ui/label";
import { Input } from "@/components/ui/input";
import { Button } from "@/components/ui/button";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
// ΓÜá∩╕Å FULL ICON IMPORT
import {
  Activity,
  Timer,
  TrendingUp,
  Dumbbell,
  Trophy,
  Medal,
  Flag,
  Flame,
  Zap,
  Heart,
  Scale,
  Calculator,
  Info,
  RotateCcw,
  AlertTriangle,
  BookOpen,
  ExternalLink,
  Waves,
  Gauge,
} from "lucide-react";
import useFaqJsonLd from "@/hooks/useFaqJsonLd";

export default function FitnessAgeCalculator() {
  // Inputs: age, gender, restingHR, vo2max
  const [inputs, setInputs] = useState({
    age: "",
    gender: "",
    restingHR: "",
    vo2max: "",
  });
  const handleInputChange = useCallback((n, v) => setInputs((p) => ({ ...p, [n]: v })), []);

  // VO2max fitness age calculation based on normative data and resting HR adjustment
  // Formula source: Jackson et al. (1990), Tanaka et al. (2001), and general cardiovascular fitness norms
  // We'll estimate fitness age by comparing VO2max to average VO2max for chronological age and gender,
  // then adjust based on resting heart rate (RHR) as a cardiovascular health indicator.

  // Normative VO2max values (ml/kg/min) by age and gender (simplified, approximate)
  // Source: Jackson et al. 1990, ACSM guidelines
  const vo2maxNorms = {
    male: [
      { ageMax: 29, vo2max: 45 },
      { ageMax: 39, vo2max: 42 },
      { ageMax: 49, vo2max: 39 },
      { ageMax: 59, vo2max: 35 },
      { ageMax: 69, vo2max: 31 },
      { ageMax: 79, vo2max: 28 },
      { ageMax: 120, vo2max: 25 },
    ],
    female: [
      { ageMax: 29, vo2max: 38 },
      { ageMax: 39, vo2max: 35 },
      { ageMax: 49, vo2max: 33 },
      { ageMax: 59, vo2max: 30 },
      { ageMax: 69, vo2max: 26 },
      { ageMax: 79, vo2max: 24 },
      { ageMax: 120, vo2max: 22 },
    ],
  };

  // Resting HR adjustment factor: lower RHR indicates better cardiovascular health
  // Typical resting HR range: 40-100 bpm
  // We'll use a simple linear adjustment: each bpm below 70 reduces fitness age by 0.3 years,
  // each bpm above 70 increases fitness age by 0.3 years.
  // Source: Tanaka et al. (2001) and general cardiovascular health literature.

  const results = useMemo(() => {
    const ageNum = Number(inputs.age);
    const rhrNum = Number(inputs.restingHR);
    const vo2maxNum = Number(inputs.vo2max);
    const gender = inputs.gender;

    if (
      !ageNum ||
      ageNum < 10 ||
      ageNum > 120 ||
      !rhrNum ||
      rhrNum < 30 ||
      rhrNum > 120 ||
      !vo2maxNum ||
      vo2maxNum < 5 ||
      vo2maxNum > 90 ||
      (gender !== "male" && gender !== "female")
    ) {
      return {
        value: null,
        label: "",
        subtext: null,
        warning: "Please enter valid inputs within realistic ranges.",
        formulaUsed:
          "Fitness Age = Chronological Age adjusted by VO2max deviation from norms and Resting Heart Rate",
      };
    }

    // Find normative VO2max for user's age and gender
    const norms = vo2maxNorms[gender];
    const normVO2max = norms.find((n) => ageNum <= n.ageMax)?.vo2max ?? norms[norms.length - 1].vo2max;

    // Calculate VO2max difference ratio
    // If user VO2max is higher than norm, fitness age is younger, else older
    // We'll assume a linear relationship: each 1 ml/kg/min difference changes fitness age by 1 year
    // This is a simplification for demonstration purposes.
    const vo2maxDiff = normVO2max - vo2maxNum;
    let fitnessAge = ageNum + vo2maxDiff;

    // Adjust fitness age based on resting heart rate
    // Each bpm above 70 adds 0.3 years, below 70 subtracts 0.3 years
    const rhrAdjustment = (rhrNum - 70) * 0.3;
    fitnessAge += rhrAdjustment;

    // Clamp fitness age between 10 and 120
    fitnessAge = Math.min(Math.max(fitnessAge, 10), 120);

    // Round to 1 decimal place
    const fitnessAgeRounded = fitnessAge.toFixed(1);

    // Subtext explanation
    const subtext = `Your estimated fitness age is based on your VO2max compared to average values for your age and gender, adjusted by your resting heart rate.`;

    return {
      value: fitnessAgeRounded,
      label: "Estimated Fitness Age (years)",
      subtext,
      warning: null,
      formulaUsed:
        "Fitness Age = Chronological Age + (Norm VO2max - Your VO2max) + 0.3 ├ù (Resting HR - 70)",
    };
  }, [inputs]);

  const faqs = [
    {
      question: "What is fitness age and why is it important?",
      answer:
        "Fitness age is an estimate of your body's physiological age based on cardiovascular fitness and heart health, rather than your chronological age. It provides insight into how well your heart, lungs, and muscles function compared to average norms. A lower fitness age than your actual age indicates better health and fitness, which is linked to reduced risk of chronic diseases and longer lifespan.",
    },
    {
      question: "How accurate is the fitness age calculated by this tool?",
      answer:
        "This calculator provides an estimate based on VO2max and resting heart rate, which are strong indicators of cardiovascular fitness. However, individual variations, genetics, lifestyle factors, and measurement accuracy can affect results. For precise assessment, clinical tests and professional evaluation are recommended.",
    },
    {
      question: "How can I improve my fitness age?",
      answer:
        "Improving your fitness age involves enhancing cardiovascular fitness and lowering resting heart rate through regular aerobic exercise, strength training, proper nutrition, stress management, and adequate sleep. Consistency and gradual progression in training are key to achieving sustainable improvements.",
    },
    {
      question: "Why do I need to input my resting heart rate?",
      answer:
        "Resting heart rate is a simple yet powerful indicator of cardiovascular health. Lower resting heart rates generally reflect a more efficient heart and better fitness. Including resting heart rate in the calculation helps refine the fitness age estimate by accounting for heart health beyond VO2max alone.",
    },
  ];
  const faqJsonLd = useFaqJsonLd(faqs);

  const widget = (
    <div className="space-y-6">
      <Card>
        <CardContent>
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
            <div>
              <Label htmlFor="age" className="flex items-center gap-1">
                <Calculator className="w-4 h-4" /> Age (years)
              </Label>
              <Input
                id="age"
                type="number"
                min={10}
                max={120}
                placeholder="e.g. 30"
                value={inputs.age}
                onChange={(e) => handleInputChange("age", e.target.value)}
              />
            </div>
            <div>
              <Label htmlFor="gender" className="flex items-center gap-1">
                <Flag className="w-4 h-4" /> Gender
              </Label>
              <Select
                onValueChange={(v) => handleInputChange("gender", v)}
                value={inputs.gender}
                id="gender"
              >
                <SelectTrigger>
                  <SelectValue placeholder="Select gender" />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="male">Male</SelectItem>
                  <SelectItem value="female">Female</SelectItem>
                </SelectContent>
              </Select>
            </div>
            <div>
              <Label htmlFor="restingHR" className="flex items-center gap-1">
                <Heart className="w-4 h-4" /> Resting Heart Rate (bpm)
              </Label>
              <Input
                id="restingHR"
                type="number"
                min={30}
                max={120}
                placeholder="e.g. 65"
                value={inputs.restingHR}
                onChange={(e) => handleInputChange("restingHR", e.target.value)}
              />
            </div>
            <div>
              <Label htmlFor="vo2max" className="flex items-center gap-1">
                <Activity className="w-4 h-4" /> VO2max (ml/kg/min)
              </Label>
              <Input
                id="vo2max"
                type="number"
                min={5}
                max={90}
                step={0.1}
                placeholder="e.g. 42.5"
                value={inputs.vo2max}
                onChange={(e) => handleInputChange("vo2max", e.target.value)}
              />
            </div>
          </div>
        </CardContent>
      </Card>

      <div className="flex flex-col sm:flex-row gap-3 pt-4">
        <Button
          className="flex-1 h-11 bg-blue-600 hover:bg-blue-700 text-white shadow-md"
          onClick={() => {
            // No special action needed, calculation is reactive
          }}
        >
          <Trophy className="mr-2 h-4 w-4" /> Calculate
        </Button>
        <Button
          variant="outline"
          onClick={() => setInputs({ age: "", gender: "", restingHR: "", vo2max: "" })}
          className="flex-1 h-11"
        >
          <RotateCcw className="mr-2 h-4 w-4" /> Reset
        </Button>
      </div>

      {/* Results */}
      {results.value && (
        <Card className="bg-gradient-to-br from-blue-50 to-indigo-100 dark:from-slate-900 dark:to-slate-950 border-blue-200 shadow-lg">
          <CardContent className="p-8 text-center">
            <p className="text-5xl font-extrabold text-blue-900 dark:text-white">{results.value}</p>
            <p className="text-lg font-semibold text-blue-800 dark:text-blue-300 mb-2">{results.label}</p>
            <p className="text-sm text-blue-700 dark:text-blue-400 leading-relaxed">{results.subtext}</p>
            {results.warning && (
              <p className="mt-4 text-red-600 dark:text-red-400 flex items-center justify-center gap-2">
                <AlertTriangle className="w-5 h-5" /> {results.warning}
              </p>
            )}
          </CardContent>
        </Card>
      )}
    </div>
  );

  const editorial = (
    <div className="space-y-12">
      <section id="what-is" className="scroll-mt-32">
        <h2 className="text-3xl font-bold mb-4 text-slate-900 dark:text-slate-100">
          Understanding Fitness Age Calculator
        </h2>
        <p className="text-slate-700 dark:text-slate-300 leading-relaxed mb-4">
          Fitness age is a powerful concept that estimates your body's physiological age based on cardiovascular fitness rather than chronological years. It reflects how well your heart, lungs, and muscles perform during physical activity, providing a more meaningful insight into your overall health and longevity. Unlike chronological age, which simply counts the years since birth, fitness age can reveal if your body is aging faster or slower than expected.
        </p>
        <p className="text-slate-700 dark:text-slate-300 leading-relaxed mb-4">
          This calculator uses your VO2max, which is the maximum amount of oxygen your body can utilize during intense exercise, and your resting heart rate (RHR), a key indicator of cardiovascular health. VO2max is widely regarded as the gold standard for measuring aerobic fitness, while RHR reflects how efficiently your heart pumps blood at rest. Together, these metrics provide a comprehensive picture of your cardiovascular system's condition.
        </p>
        <p className="text-slate-700 dark:text-slate-300 leading-relaxed mb-4">
          By comparing your VO2max to normative values for your age and gender, and adjusting for your resting heart rate, the calculator estimates your fitness age. A fitness age lower than your actual age suggests superior cardiovascular health and fitness, which is associated with reduced risk of chronic diseases such as heart disease, diabetes, and certain cancers. Conversely, a higher fitness age may indicate the need for lifestyle changes to improve your health.
        </p>
        <p className="text-slate-700 dark:text-slate-300 leading-relaxed">
