    }

    const lengthMeters = convertToMeters(lengthNum, inputs.unit);
    const spec = cableSpecs[inputs.cableType];
    if (!spec) {
      return {
        primary: "ΓÇö",
        secondary: "",
        details: "Selected cable type is not supported.",
        feedback: "",
