import React, { useState, useEffect, useRef } from "react";
import { Gamepad2, Maximize2, Minimize2 } from "lucide-react";
import GameStartOverlay from "./GameStartOverlay";
import CalculatorVerticalLayout from "../templates/CalculatorVerticalLayout";
import useFaqJsonLd from "../../hooks/useFaqJsonLd";
import { useTheme } from "next-themes";
import { Button } from "@/components/ui/button";

// --- Game Constants ---
const CANVAS_WIDTH = 600;
const CANVAS_HEIGHT = 600;
const GRID_SIZE = 40;
const ROWS = CANVAS_HEIGHT / GRID_SIZE; // 15
const COLS = CANVAS_WIDTH / GRID_SIZE; // 15

const INITIAL_SPEED_MAP = {
  easy: 1,
  medium: 2,
  hard: 3,
};

type Difficulty = "easy" | "medium" | "hard";
type GameState = "MENU" | "PLAYING" | "GAME_OVER";

type LaneType = "safe" | "road" | "water";

interface Lane {
  type: LaneType;
  y: number;
  speed: number; // 0 for safe
  direction: 1 | -1;
  objects: GameObject[];
  color: string;
}

interface GameObject {
  x: number;
  width: number;
  type: "car" | "log";
}

// --- Crossy Street Board Component ---
function CrossyStreetBoard({
  title,
  description,
}: {
  title: string;
  description: string;
}) {
  const { theme } = useTheme();
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  // --- State ---
  const [gameState, setGameState] = useState<GameState>("MENU");
  const [difficulty, setDifficulty] = useState<Difficulty>("medium");
  const [score, setScore] = useState(0);
  const [highScore, setHighScore] = useState(0);
  const [isFullscreen, setIsFullscreen] = useState(false);

  // Game Logic Refs
  const playerRef = useRef({ x: 7, y: 14 }); // Grid coordinates
  const lanesRef = useRef<Lane[]>([]);
  const animationFrameRef = useRef<number | null>(null);

  // --- Effects ---

  // Load High Score and Init Level
  useEffect(() => {
    const saved = localStorage.getItem("crossy-street-highscore");
    if (saved) setHighScore(parseInt(saved, 10));

    // Generate initial level for background
    generateLevel("medium");
    // Force a draw
    setTimeout(() => draw(), 50);
  }, []);

  // Update High Score
  useEffect(() => {
    if (score > highScore) {
      setHighScore(score);
      localStorage.setItem("crossy-street-highscore", score.toString());
    }
  }, [score, highScore]);

  // Handle Resize
  useEffect(() => {
    const handleResize = () => {
      if (containerRef.current && canvasRef.current) {
        if (document.fullscreenElement && containerRef.current === document.fullscreenElement) {
          canvasRef.current.style.width = "100%";
          canvasRef.current.style.height = "100%";
          return;
        }

        const { clientWidth } = containerRef.current;
        const width = Math.min(clientWidth, 600);
        const height = width; // Square

        canvasRef.current.style.width = `${width}px`;
        canvasRef.current.style.height = `${height}px`;
      }
    };

    window.addEventListener("resize", handleResize);
    handleResize();
    setTimeout(handleResize, 100);

    return () => window.removeEventListener("resize", handleResize);
  }, [gameState, theme, isFullscreen]);

  const toggleFullscreen = () => {
    if (!containerRef.current) return;

    if (!document.fullscreenElement) {
      containerRef.current.requestFullscreen().catch((err) => {
        console.error(`Error attempting to enable fullscreen: ${err.message}`);
      });
      setIsFullscreen(true);
    } else {
      document.exitFullscreen();
      setIsFullscreen(false);
    }
  };

  useEffect(() => {
    const onFullscreenChange = () => {
      setIsFullscreen(!!document.fullscreenElement);
    };
    document.addEventListener("fullscreenchange", onFullscreenChange);
    return () => document.removeEventListener("fullscreenchange", onFullscreenChange);
  }, []);

  // Game Loop
  useEffect(() => {
    if (gameState === "PLAYING") {
      containerRef.current?.focus();
      const loop = () => {
        update();
        draw();
        animationFrameRef.current = requestAnimationFrame(loop);
      };
      animationFrameRef.current = requestAnimationFrame(loop);
    } else {
      if (animationFrameRef.current) cancelAnimationFrame(animationFrameRef.current);
      draw();
    }

    return () => {
      if (animationFrameRef.current) cancelAnimationFrame(animationFrameRef.current);
    };
  }, [gameState, difficulty, theme]);

  // Keyboard Controls
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (gameState !== "PLAYING") return;

      const p = playerRef.current;
      switch (e.key) {
        case "ArrowUp":
        case "w":
          p.y--;
          setScore(s => Math.max(s, 14 - p.y)); // Simple scoring based on max distance
          break;
        case "ArrowDown":
        case "s":
          if (p.y < ROWS - 1) p.y++;
          break;
        case "ArrowLeft":
        case "a":
          if (p.x > 0) p.x--;
          break;
        case "ArrowRight":
        case "d":
          if (p.x < COLS - 1) p.x++;
          break;
      }
    };

    window.addEventListener("keydown", handleKeyDown);
    return () => window.removeEventListener("keydown", handleKeyDown);
  }, [gameState]);

  // Touch Controls
  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    let startX = 0;
    let startY = 0;

    const handleTouchStart = (e: TouchEvent) => {
      startX = e.touches[0].clientX;
      startY = e.touches[0].clientY;
    };

    const handleTouchEnd = (e: TouchEvent) => {
      if (gameState !== "PLAYING") return;

      const endX = e.changedTouches[0].clientX;
      const endY = e.changedTouches[0].clientY;
      const diffX = endX - startX;
      const diffY = endY - startY;

      const p = playerRef.current;

      if (Math.abs(diffX) > Math.abs(diffY)) {
        // Horizontal
        if (Math.abs(diffX) > 30) { // Threshold
          if (diffX > 0 && p.x < COLS - 1) p.x++;
          else if (diffX < 0 && p.x > 0) p.x--;
        }
      } else {
        // Vertical
        if (Math.abs(diffY) > 30) {
          if (diffY < 0) {
            p.y--;
            setScore(s => Math.max(s, 14 - p.y));
          }
          else if (diffY > 0 && p.y < ROWS - 1) p.y++;
        } else {
          // Tap = Forward
          p.y--;
          setScore(s => Math.max(s, 14 - p.y));
        }
      }
    };

    canvas.addEventListener("touchstart", handleTouchStart, { passive: false });
    canvas.addEventListener("touchend", handleTouchEnd, { passive: false });

    return () => {
      canvas.removeEventListener("touchstart", handleTouchStart);
      canvas.removeEventListener("touchend", handleTouchEnd);
    };
  }, [gameState]);


  // --- Game Logic ---

  const initGame = (diff: Difficulty) => {
    setDifficulty(diff);
    setScore(0);
    playerRef.current = { x: 7, y: 14 };
    generateLevel(diff); // Generate before setting state
    setGameState("PLAYING");
  };

  const generateLevel = (diff: Difficulty) => {
    const lanes: Lane[] = [];
    const baseSpeed = INITIAL_SPEED_MAP[diff];

    for (let i = 0; i < ROWS; i++) {
      // Bottom lanes are safe
      if (i >= 13) {
        lanes.push({ type: "safe", y: i, speed: 0, direction: 1, objects: [], color: "" });
        continue;
      }

      let type: LaneType = "safe";
      let speed = 0;
      const objects: GameObject[] = [];

      // Fixed layout pattern
      if ((i >= 9 && i <= 12) || (i >= 0 && i <= 2)) {
        type = "road";
        speed = (baseSpeed + Math.random() * 2) * (i % 2 === 0 ? 1 : 1.5);
      } else if (i >= 4 && i <= 7) {
        type = "water";
        speed = (baseSpeed + Math.random() * 1.5) * (i % 2 === 0 ? 1 : 1.2);
      }

      const direction = i % 2 === 0 ? 1 : -1;

      if (type === "road") {
        const numCars = 2 + Math.floor(Math.random() * 2);
        for (let j = 0; j < numCars; j++) {
          objects.push({ x: j * 200 + Math.random() * 50, width: 40, type: "car" });
        }
      } else if (type === "water") {
        const numLogs = 2 + Math.floor(Math.random() * 2);
        for (let j = 0; j < numLogs; j++) {
          objects.push({ x: j * 220 + Math.random() * 50, width: 80 + Math.random() * 40, type: "log" });
        }
      }

      lanes.push({
        type,
        y: i,
        speed: type === "safe" ? 0 : speed,
        direction,
        objects,
        color: type === "safe" ? "#22c55e" : type === "road" ? "#334155" : "#3b82f6"
      });
    }
    lanesRef.current = lanes;
  };

  const update = () => {
    const player = playerRef.current;

    // Check Win (Top reached)
    if (player.y < 0) {
      setScore(s => s + 50); // Bonus
      player.y = 14; // Reset to bottom
      // Increase difficulty slightly?
    }

    // Move Objects
    lanesRef.current.forEach(lane => {
      if (lane.speed === 0) return;

      lane.objects.forEach(obj => {
        obj.x += lane.speed * lane.direction;

        // Wrap
        if (lane.direction === 1 && obj.x > CANVAS_WIDTH) obj.x = -obj.width;
        if (lane.direction === -1 && obj.x < -obj.width) obj.x = CANVAS_WIDTH;
      });
    });

    // Collisions
    const currentLane = lanesRef.current.find(l => l.y === player.y);
    if (currentLane) {
      const playerRect = {
        x: player.x * GRID_SIZE + 5,
        y: player.y * GRID_SIZE + 5,
        w: GRID_SIZE - 10,
        h: GRID_SIZE - 10
      };

      if (currentLane.type === "road") {
        // Check Car hit
        const hit = currentLane.objects.some(obj => {
          return (
            playerRect.x < obj.x + obj.width &&
            playerRect.x + playerRect.w > obj.x
          );
        });
        if (hit) setGameState("GAME_OVER");
      } else if (currentLane.type === "water") {
        // Check Log ride
        const onLog = currentLane.objects.some(obj => {
          return (
            playerRect.x + playerRect.w / 2 > obj.x &&
            playerRect.x + playerRect.w / 2 < obj.x + obj.width
          );
        });

        if (onLog) {
          // Move player with log
          player.x += (currentLane.speed * currentLane.direction) / GRID_SIZE;
          // Clamp
          if (player.x < 0 || player.x >= COLS) setGameState("GAME_OVER");
        } else {
          // Drown
          setGameState("GAME_OVER");
        }
      }
    }
  };

  const draw = () => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext("2d");
    if (!ctx) return;

    const isDark = theme === "dark";

    // Colors
    const colors = {
      bg: isDark ? "#0f172a" : "#f8fafc",
      safe: isDark ? "#166534" : "#86efac",
      road: isDark ? "#1e293b" : "#94a3b8",
      water: isDark ? "#1e40af" : "#93c5fd",
      player: isDark ? "#facc15" : "#eab308",
      car: isDark ? "#ef4444" : "#dc2626",
      log: isDark ? "#78350f" : "#92400e",
    };

    // Clear
    ctx.fillStyle = colors.bg;
    ctx.fillRect(0, 0, CANVAS_WIDTH, CANVAS_HEIGHT);

    // Draw Lanes
    if (lanesRef.current.length > 0) {
      lanesRef.current.forEach(lane => {
        ctx.fillStyle = lane.type === "safe" ? colors.safe : lane.type === "road" ? colors.road : colors.water;
        ctx.fillRect(0, lane.y * GRID_SIZE, CANVAS_WIDTH, GRID_SIZE);

        // Draw Objects
        lane.objects.forEach(obj => {
          ctx.fillStyle = obj.type === "car" ? colors.car : colors.log;
          // Simple shadows
          ctx.shadowColor = "rgba(0,0,0,0.2)";
          ctx.shadowBlur = 4;
          ctx.fillRect(obj.x, lane.y * GRID_SIZE + 5, obj.width, GRID_SIZE - 10);
          ctx.shadowBlur = 0;
        });
      });
    }

    // Draw Player
    if (gameState !== "MENU") {
      ctx.fillStyle = colors.player;
      ctx.shadowColor = colors.player;
      ctx.shadowBlur = 10;
      const px = playerRef.current.x * GRID_SIZE;
      const py = playerRef.current.y * GRID_SIZE;
      ctx.fillRect(px + 5, py + 5, GRID_SIZE - 10, GRID_SIZE - 10);
      ctx.shadowBlur = 0;
    }

    // Draw UI
    if (gameState === "PLAYING") {
      ctx.fillStyle = "#ffffff";
      ctx.font = "bold 20px Arial";
      ctx.strokeStyle = "#000000";
      ctx.lineWidth = 3;
      ctx.strokeText(`Score: ${score}`, 20, 30);
      ctx.fillText(`Score: ${score}`, 20, 30);
    }
  };

  return (
    <div className="flex flex-col gap-4 w-full max-w-[800px] mx-auto z-10">
      <GameStartOverlay
        isPlaying={gameState === "PLAYING"}
        isGameOver={gameState === "GAME_OVER"}
        score={score}
        highScore={highScore}
        onStart={initGame}
        onRestart={initGame}
        gameName={title}
      />
      <div
        ref={containerRef}
        className={`relative w-full max-w-[600px] mx-auto bg-slate-50 dark:bg-slate-950 rounded-xl overflow-hidden shadow-2xl border border-slate-200 dark:border-slate-800 focus:outline-none ${isFullscreen ? "flex items-center justify-center h-screen max-w-none rounded-none border-0" : "aspect-square"
          }`}
        tabIndex={0}
      >
        <canvas
          ref={canvasRef}
          width={CANVAS_WIDTH}
          height={CANVAS_HEIGHT}
          className={`block touch-none ${isFullscreen ? "w-full h-full object-contain" : "w-full h-full"}`}
        />

        {/* Fullscreen Toggle */}
        {!isFullscreen && (
          <Button
            variant="ghost"
            size="icon"
            className="absolute top-2 right-2 z-10 text-slate-500 hover:text-slate-900 dark:text-slate-400 dark:hover:text-white"
            onClick={toggleFullscreen}
          >
            <Maximize2 className="w-6 h-6" />
          </Button>
        )}

        {isFullscreen && (
          <Button
            variant="ghost"
            size="icon"
            className="absolute top-4 right-4 z-10 text-white/50 hover:text-white hover:bg-white/10"
            onClick={toggleFullscreen}
          >
            <Minimize2 className="w-8 h-8" />
          </Button>
        )}

        {/* Overlays */}

      </div>
    </div>
  );
}

