        )}
      </div>

      <p className="text-sm text-slate-500 dark:text-slate-400 text-center max-w-[340px]">
        Use arrow keys or swipe to move tiles. Merge same numbers to reach 2048!
      </p>
    </div>
  );
}

// ΓöÇΓöÇΓöÇ Exported Page Component ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
export default function Game2048Classic({
  title = "2048 Classic",
