export default function HangmanExtremeGame({
  title = "Hangman Extreme",
  description = "Classic Hangman word game with 6 categories and 3 difficulty levels. Guess the hidden word before the man is fully drawn!",
}: {
  title?: string;
  description?: string;
}) {
  return (
    <CalculatorVerticalLayout
      title={title}
      description={description}
      widget={<HangmanBoard />}
      editorial={editorial}
      onThisPage={[
        { id: "guide", label: "How to Play" },
        { id: "tips", label: "Strategy Tips" },
        { id: "faq", label: "FAQ" },
      ]}
      showTopBanner={true}
      showSidebar={true}
      showBottomBanner={true}
    />
  );
}

import React, { useState, useCallback, useEffect } from "react";
import CalculatorVerticalLayout from "@/components/templates/CalculatorVerticalLayout";

// Ludo path for each color (15 steps on outer track + 6 home stretch)
const BOARD_SIZE = 15;
const OUTER_PATH_LENGTH = 52;

// Starting square index on the outer path for each color
const COLOR_START: Record<string, number> = { red: 0, blue: 13, green: 26, yellow: 39 };
// Safe squares (star squares) on the outer path
const SAFE_SQUARES = new Set([0, 8, 13, 21, 26, 34, 39, 47]);

const COLORS = ["red", "blue", "green", "yellow"] as const;
type Color = typeof COLORS[number];
type TokenState = "home" | "active" | "done";
interface Token { color: Color; id: number; pos: number; state: TokenState }

const CSS: Record<Color, string> = {
  red: "#ef4444", blue: "#3b82f6", green: "#22c55e", yellow: "#eab308"
};
const DARK: Record<Color, string> = {
  red: "#991b1b", blue: "#1d4ed8", green: "#15803d", yellow: "#a16207"
};

function initTokens(): Token[] {
  return COLORS.flatMap(color =>
    [0,1,2,3].map(id => ({ color, id, pos: -1, state: "home" as TokenState }))
  );
}

function advancePos(pos: number, steps: number, color: Color): number {
  return (pos + steps) % OUTER_PATH_LENGTH;
}

// Build a simple board layout mapping - simplified visual representation
function LudoBoard({ tokens, onTokenClick, activeColor, validTokenIds }: {
  tokens: Token[]; onTokenClick: (t: Token) => void;
  activeColor: Color; validTokenIds: Set<number>;
}) {
  const tokensByColor = Object.fromEntries(
    COLORS.map(c => [c, tokens.filter(t => t.color === c)])
  );

  return (
    <div className="relative">
      {/* Home bases */}
      <div className="grid grid-cols-2 gap-2 mb-4">
        {COLORS.map(color => (
          <div key={color} style={{ background: CSS[color], opacity: 0.15, border:`2px solid ${CSS[color]}` }}
            className="rounded-lg p-3 flex flex-wrap gap-2">
            <span style={{color:CSS[color]}} className="text-xs font-bold w-full">{color.toUpperCase()}</span>
            {tokensByColor[color].filter(t => t.state === "home").map(t => (
              <button key={t.id} onClick={() => onTokenClick(t)}
                disabled={!validTokenIds.has(t.id)}
                style={{ background: validTokenIds.has(t.id) ? CSS[color] : DARK[color],
                  border: `2px solid ${validTokenIds.has(t.id) ? "white" : "transparent"}`,
                  boxShadow: validTokenIds.has(t.id) ? `0 0 8px ${CSS[color]}` : "none" }}
                className="w-8 h-8 rounded-full text-white text-xs font-bold transition-all hover:scale-110">
                {t.id+1}
              </button>
            ))}
          </div>
        ))}
      </div>

      {/* Active tokens */}
      <div className="bg-slate-800 rounded-lg p-3">
        <div className="text-xs text-slate-400 mb-2">Active Tokens (position on track)</div>
        <div className="flex flex-wrap gap-2">
          {tokens.filter(t => t.state === "active").map(t => (
            <button key={`${t.color}-${t.id}`} onClick={() => onTokenClick(t)}
              disabled={!validTokenIds.has(t.id) || t.color !== activeColor}
              style={{ background: CSS[t.color], border: `2px solid ${validTokenIds.has(t.id) && t.color===activeColor ? "white":"transparent"}`,
                boxShadow: validTokenIds.has(t.id) && t.color===activeColor ? `0 0 8px ${CSS[t.color]}` : "none" }}
              className="w-10 h-10 rounded-full text-white text-xs font-bold flex flex-col items-center justify-center transition-all hover:scale-110">
              <span>{t.color[0].toUpperCase()}{t.id+1}</span>
              <span className="text-[9px] opacity-80">#{t.pos}</span>
            </button>
          ))}
          {tokens.filter(t => t.state === "active").length === 0 &&
            <span className="text-slate-500 text-xs">No active tokens yet</span>}
        </div>
      </div>

      {/* Done tokens */}
      {tokens.some(t => t.state === "done") && (
        <div className="mt-2 text-sm text-center">
          {COLORS.map(c => {
            const done = tokens.filter(t => t.color === c && t.state === "done").length;
            return done > 0 ? <span key={c} style={{color:CSS[c]}} className="mr-2">{c}: {done}/4 ≡ƒÅá</span> : null;
          })}
        </div>
      )}
    </div>
  );
}

function rollDie(): number { return Math.floor(Math.random() * 6) + 1; }

function LudoGame() {
  const [tokens, setTokens] = useState<Token[]>(initTokens);
  const [die, setDie] = useState<number | null>(null);
  const [turn, setTurn] = useState<Color>("red");
  const [phase, setPhase] = useState<"roll"|"move">("roll");
  const [winner, setWinner] = useState<Color | null>(null);
  const [message, setMessage] = useState("Red's turn! Roll the die.");
  const [isAI, setIsAI] = useState(false);

  const humanColor: Color = "red";

  const getValidMoves = useCallback((tks: Token[], color: Color, rolled: number): number[] => {
    const colorTokens = tks.filter(t => t.color === color);
    const valid: number[] = [];
    for (const t of colorTokens) {
      if (t.state === "done") continue;
      if (t.state === "home" && rolled === 6) valid.push(t.id);
      if (t.state === "active") {
        const newPos = advancePos(t.pos, rolled, color);
        // Check if overshoots (simplified: if crosses start again it's home stretch)
        valid.push(t.id);
      }
    }
    return valid;
  }, []);

  const moveToken = useCallback((tokenId: number) => {
    if (phase !== "move" || die === null) return;
    setTokens(prev => {
      const next = prev.map(t => {
        if (t.id !== tokenId || t.color !== turn) return t;
        if (t.state === "home" && die === 6) {
          return { ...t, state: "active" as TokenState, pos: COLOR_START[turn] };
        }
        if (t.state === "active") {
          const newPos = advancePos(t.pos, die, turn);
          // Check if token completed the circuit (52 steps from start)
          const startPos = COLOR_START[turn];
          const distFromStart = (t.pos - startPos + OUTER_PATH_LENGTH) % OUTER_PATH_LENGTH;
          const newDist = distFromStart + die;
          if (newDist >= OUTER_PATH_LENGTH) {
            return { ...t, state: "done" as TokenState, pos: 99 };
          }
          return { ...t, pos: newPos };
        }
        return t;
      });

      // Check win
      const turnTokens = next.filter(t => t.color === turn);
      if (turnTokens.every(t => t.state === "done")) {
        setWinner(turn);
        setMessage(`≡ƒÅå ${turn.toUpperCase()} wins!`);
        return next;
      }

      // Next turn
      const nextColor = COLORS[(COLORS.indexOf(turn) + 1) % 4];
      setTurn(nextColor);
      setPhase("roll");
      setDie(null);
      setMessage(`${nextColor.toUpperCase()}'s turn! Roll the die.`);
      return next;
    });
  }, [phase, die, turn]);

  const handleRoll = useCallback(() => {
    if (phase !== "roll") return;
    const rolled = rollDie();
    setDie(rolled);
    const valid = getValidMoves(tokens, turn, rolled);
    if (valid.length === 0) {
      setMessage(`${turn.toUpperCase()} rolled ${rolled} - no valid moves. Passing.`);
      setTimeout(() => {
        const nextColor = COLORS[(COLORS.indexOf(turn) + 1) % 4];
        setTurn(nextColor);
        setPhase("roll");
        setDie(null);
        setMessage(`${nextColor.toUpperCase()}'s turn! Roll the die.`);
      }, 1000);
    } else if (valid.length === 1 && tokens.find(t => t.id === valid[0] && t.color === turn)?.state === "active"
      && tokens.filter(t => t.color === turn && t.state === "home").length === 0) {
      // Auto-move if only one option
      setPhase("move");
      setTimeout(() => moveToken(valid[0]), 300);
    } else {
      setPhase("move");
      setMessage(`Rolled ${rolled}! Choose a token to move.`);
    }
  }, [phase, tokens, turn, getValidMoves, moveToken]);

  // AI turn
  useEffect(() => {
    if (turn !== humanColor && phase === "roll" && !winner) {
      setIsAI(true);
      const t = setTimeout(() => {
        handleRoll();
        setIsAI(false);
      }, 800);
      return () => clearTimeout(t);
    }
  }, [turn, phase, winner, handleRoll]);

  useEffect(() => {
    if (turn !== humanColor && phase === "move" && die !== null && !winner) {
      setIsAI(true);
      const valid = getValidMoves(tokens, turn, die);
      if (valid.length > 0) {
        const t = setTimeout(() => {
          moveToken(valid[Math.floor(Math.random() * valid.length)]);
          setIsAI(false);
        }, 600);
        return () => clearTimeout(t);
      }
    }
  }, [turn, phase, die, tokens, winner, getValidMoves, moveToken]);

  const validIds = phase === "move" && die !== null && turn === humanColor
    ? new Set(getValidMoves(tokens, turn, die))
    : new Set<number>();

  const handleTokenClick = useCallback((t: Token) => {
    if (t.color !== humanColor || phase !== "move" || !validIds.has(t.id)) return;
    moveToken(t.id);
  }, [humanColor, phase, validIds, moveToken]);

  const dieEmoji = ["","ΓÜÇ","ΓÜü","ΓÜé","ΓÜâ","ΓÜä","ΓÜà"];

  return (
    <div className="flex flex-col items-center gap-4 p-4 max-w-sm mx-auto">
      <div className="text-center">
        <div className="text-lg font-bold" style={{ color: CSS[turn] }}>{message}</div>
        {isAI && <div className="text-xs text-slate-500 animate-pulse">AI is thinking...</div>}
      </div>

      {winner && (
        <div className="bg-yellow-500 text-black font-bold text-xl px-6 py-3 rounded-xl animate-bounce">
          ≡ƒÅå {winner.toUpperCase()} WINS!
          <button onClick={() => { setTokens(initTokens()); setTurn("red"); setPhase("roll"); setDie(null); setWinner(null); setMessage("Red's turn! Roll the die."); }}
            className="block text-sm font-normal mt-1 underline">Play Again</button>
        </div>
      )}

      {/* Die */}
      <div className="flex items-center gap-4">
        <div className="text-5xl">{die ? dieEmoji[die] : "≡ƒÄ▓"}</div>
        {phase === "roll" && turn === humanColor && !winner && (
          <button onClick={handleRoll}
            className="bg-blue-600 hover:bg-blue-500 text-white font-bold px-6 py-3 rounded-xl text-lg transition-all hover:scale-105">
            Roll!
          </button>
        )}
      </div>

      <LudoBoard tokens={tokens} onTokenClick={handleTokenClick}
        activeColor={turn} validTokenIds={validIds} />

      <p className="text-xs text-slate-500 text-center">
        You are RED. Roll 6 to enter a token. Move tokens around the board to bring them home!
      </p>
    </div>
  );
}

export default function LudoPartyGame() {
  return (
    <CalculatorVerticalLayout
      title="Ludo Party"
      description="Play the classic Ludo board game! Roll dice and race your tokens to the center. Play against AI opponents in this fun multiplayer board game."
      canonical="https://www.smartkitnow.com/games/ludo-party"
      widget={<LudoGame />}
      editorial={
        <div className="space-y-3 text-sm text-slate-600 dark:text-slate-300">
          <h2 className="text-xl font-bold">How to Play Ludo Party</h2>
          <p>You play as Red. Roll the die and move your tokens around the board. Roll a 6 to enter a new token from home base.</p>
          <p><strong>Goal:</strong> Get all 4 of your tokens to the center (home) before opponents do.</p>
          <p>Landing on an opponent's token sends it back to their home base!</p>
        </div>
      }
      contentMaxWidth="max-w-sm"
    />
  );
}

import React, { useState, useEffect, useRef, useCallback } from "react";
import CalculatorVerticalLayout from "@/components/templates/CalculatorVerticalLayout";

const MAZE_SIZE = 15;
const CELL_SIZE = 1;
const FOV = Math.PI / 3;
const NUM_RAYS = 320;
const HALF_FOV = FOV / 2;
const MAX_DEPTH = 20;
const MINIMAP_SCALE = 10;

type MazeCell = 0 | 1; // 0 = open, 1 = wall

function generateMaze(size: number): MazeCell[][] {
  const maze: MazeCell[][] = Array.from({ length: size }, () =>
    Array(size).fill(1)
  );

  const visited: boolean[][] = Array.from({ length: size }, () =>
    Array(size).fill(false)
  );

  function carve(x: number, y: number) {
    visited[y][x] = true;
    maze[y][x] = 0;
    const dirs = [
      [0, -2], [0, 2], [-2, 0], [2, 0],
    ].sort(() => Math.random() - 0.5);

    for (const [dx, dy] of dirs) {
      const nx = x + dx;
      const ny = y + dy;
      if (nx > 0 && nx < size - 1 && ny > 0 && ny < size - 1 && !visited[ny][nx]) {
        maze[y + dy / 2][x + dx / 2] = 0;
        carve(nx, ny);
      }
    }
  }

  carve(1, 1);
  maze[size - 2][size - 2] = 0;
  return maze;
}

interface PlayerState {
  x: number;
  y: number;
  angle: number;
}

function GameUI() {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const minimapRef = useRef<HTMLCanvasElement>(null);
  const animRef = useRef<number>(0);
  const keysRef = useRef<Set<string>>(new Set());
  const [maze, setMaze] = useState<MazeCell[][]>(() => generateMaze(MAZE_SIZE));
  const [player, setPlayer] = useState<PlayerState>({ x: 1.5, y: 1.5, angle: 0 });
  const [won, setWon] = useState(false);
  const [elapsed, setElapsed] = useState(0);
  const [bestTime, setBestTime] = useState<number | null>(() => {
    const s = localStorage.getItem("hs_maze-runner-3d");
    return s ? parseInt(s) : null;
  });
  const startTimeRef = useRef<number>(Date.now());
  const playerRef = useRef<PlayerState>({ x: 1.5, y: 1.5, angle: 0 });
  const mazeRef = useRef<MazeCell[][]>(maze);
  const wonRef = useRef(false);

  const resetGame = useCallback(() => {
    const newMaze = generateMaze(MAZE_SIZE);
    const newPlayer = { x: 1.5, y: 1.5, angle: 0 };
    setMaze(newMaze);
    setPlayer(newPlayer);
    setWon(false);
    setElapsed(0);
    wonRef.current = false;
    playerRef.current = newPlayer;
    mazeRef.current = newMaze;
    startTimeRef.current = Date.now();
  }, []);

  useEffect(() => {
    mazeRef.current = maze;
  }, [maze]);

  useEffect(() => {
    if (won) return;
    const interval = setInterval(() => {
      setElapsed(Math.floor((Date.now() - startTimeRef.current) / 1000));
    }, 500);
    return () => clearInterval(interval);
  }, [won]);

  const castRay = useCallback((px: number, py: number, angle: number, mazeData: MazeCell[][]): { dist: number; side: number } => {
    const rayDirX = Math.cos(angle);
    const rayDirY = Math.sin(angle);
    let mapX = Math.floor(px);
    let mapY = Math.floor(py);
    const deltaDistX = Math.abs(1 / (rayDirX || 0.0001));
    const deltaDistY = Math.abs(1 / (rayDirY || 0.0001));
    let stepX: number, stepY: number;
    let sideDistX: number, sideDistY: number;

    if (rayDirX < 0) { stepX = -1; sideDistX = (px - mapX) * deltaDistX; }
    else { stepX = 1; sideDistX = (mapX + 1 - px) * deltaDistX; }
    if (rayDirY < 0) { stepY = -1; sideDistY = (py - mapY) * deltaDistY; }
    else { stepY = 1; sideDistY = (mapY + 1 - py) * deltaDistY; }

    let side = 0;
    let hit = false;
    let depth = 0;

    while (!hit && depth < MAX_DEPTH) {
      if (sideDistX < sideDistY) { sideDistX += deltaDistX; mapX += stepX; side = 0; }
      else { sideDistY += deltaDistY; mapY += stepY; side = 1; }
      if (mapX >= 0 && mapX < MAZE_SIZE && mapY >= 0 && mapY < MAZE_SIZE && mazeData[mapY][mapX] === 1) hit = true;
      depth++;
    }

    const dist = side === 0
      ? (mapX - px + (1 - stepX) / 2) / (rayDirX || 0.0001)
      : (mapY - py + (1 - stepY) / 2) / (rayDirY || 0.0001);

    return { dist: Math.abs(dist), side };
  }, []);

  const render = useCallback(() => {
    const canvas = canvasRef.current;
    const minimap = minimapRef.current;
    if (!canvas || !minimap) return;
    const ctx = canvas.getContext("2d");
    const mctx = minimap.getContext("2d");
    if (!ctx || !mctx) return;

    const W = canvas.width;
    const H = canvas.height;
    const p = playerRef.current;
    const mazeData = mazeRef.current;

    ctx.fillStyle = "#1a1a2e";
    ctx.fillRect(0, 0, W, H / 2);
    ctx.fillStyle = "#4a3728";
    ctx.fillRect(0, H / 2, W, H / 2);

    const colWidth = W / NUM_RAYS;
    for (let i = 0; i < NUM_RAYS; i++) {
      const rayAngle = p.angle - HALF_FOV + (i / NUM_RAYS) * FOV;
      const { dist, side } = castRay(p.x, p.y, rayAngle, mazeData);
      const correctedDist = dist * Math.cos(rayAngle - p.angle);
      const wallH = Math.min(H, H / correctedDist);
      const top = (H - wallH) / 2;

      const isExit = Math.floor(p.x + Math.cos(rayAngle) * dist) === MAZE_SIZE - 2 &&
        Math.floor(p.y + Math.sin(rayAngle) * dist) === MAZE_SIZE - 2;

      let baseColor = isExit ? 220 : 180;
      if (side === 1) baseColor = Math.floor(baseColor * 0.7);
      const shade = Math.max(30, Math.min(baseColor, baseColor - dist * 8));
      ctx.fillStyle = isExit ? `rgb(${shade}, ${Math.floor(shade * 0.3)}, 0)` : `rgb(${shade}, ${shade}, ${Math.floor(shade * 0.8)})`;
      ctx.fillRect(i * colWidth, top, colWidth + 1, wallH);
    }

    const mm = MINIMAP_SCALE;
    mctx.clearRect(0, 0, minimap.width, minimap.height);
    mctx.fillStyle = "rgba(0,0,0,0.7)";
    mctx.fillRect(0, 0, minimap.width, minimap.height);
    for (let y = 0; y < MAZE_SIZE; y++) {
      for (let x = 0; x < MAZE_SIZE; x++) {
        if (mazeData[y][x] === 1) {
          mctx.fillStyle = "#888";
          mctx.fillRect(x * mm, y * mm, mm - 1, mm - 1);
        }
        if (x === MAZE_SIZE - 2 && y === MAZE_SIZE - 2) {
          mctx.fillStyle = "#f80";
          mctx.fillRect(x * mm, y * mm, mm - 1, mm - 1);
        }
      }
    }
    mctx.fillStyle = "#0ff";
    mctx.beginPath();
    mctx.arc(p.x * mm, p.y * mm, mm / 2, 0, Math.PI * 2);
    mctx.fill();
    mctx.strokeStyle = "#0ff";
    mctx.lineWidth = 1;
    mctx.beginPath();
    mctx.moveTo(p.x * mm, p.y * mm);
    mctx.lineTo((p.x + Math.cos(p.angle) * 1.5) * mm, (p.y + Math.sin(p.angle) * 1.5) * mm);
    mctx.stroke();
  }, [castRay]);

  const updatePlayer = useCallback(() => {
    if (wonRef.current) return;
    const keys = keysRef.current;
    const speed = 0.05;
    const rotSpeed = 0.04;
    const p = { ...playerRef.current };
    const mazeData = mazeRef.current;

    if (keys.has("ArrowLeft") || keys.has("a") || keys.has("A")) p.angle -= rotSpeed;
    if (keys.has("ArrowRight") || keys.has("d") || keys.has("D")) p.angle += rotSpeed;

    let moveX = 0;
    let moveY = 0;
    if (keys.has("ArrowUp") || keys.has("w") || keys.has("W")) {
      moveX += Math.cos(p.angle) * speed;
      moveY += Math.sin(p.angle) * speed;
    }
    if (keys.has("ArrowDown") || keys.has("s") || keys.has("S")) {
      moveX -= Math.cos(p.angle) * speed;
      moveY -= Math.sin(p.angle) * speed;
    }

    const nx = p.x + moveX;
    const ny = p.y + moveY;
    const margin = 0.25;
    if (mazeData[Math.floor(p.y)][Math.floor(nx + (moveX > 0 ? margin : -margin))] === 0) p.x = nx;
    if (mazeData[Math.floor(ny + (moveY > 0 ? margin : -margin))][Math.floor(p.x)] === 0) p.y = ny;

    playerRef.current = p;
    setPlayer({ ...p });

    if (Math.floor(p.x) === MAZE_SIZE - 2 && Math.floor(p.y) === MAZE_SIZE - 2) {
      wonRef.current = true;
      setWon(true);
      const t = Math.floor((Date.now() - startTimeRef.current) / 1000);
      setBestTime(prev => {
        const best = prev === null || t < prev ? t : prev;
        try { localStorage.setItem("hs_maze-runner-3d", String(best)); } catch {}
        return best;
      });
    }
  }, []);

  useEffect(() => {
    const onKey = (e: KeyboardEvent) => { keysRef.current.add(e.key); e.preventDefault(); };
    const onKeyUp = (e: KeyboardEvent) => keysRef.current.delete(e.key);
    window.addEventListener("keydown", onKey);
    window.addEventListener("keyup", onKeyUp);
    return () => { window.removeEventListener("keydown", onKey); window.removeEventListener("keyup", onKeyUp); };
  }, []);

  useEffect(() => {
    let running = true;
    const loop = () => {
      if (!running) return;
      updatePlayer();
      render();
      animRef.current = requestAnimationFrame(loop);
    };
    animRef.current = requestAnimationFrame(loop);
    return () => { running = false; cancelAnimationFrame(animRef.current); };
  }, [updatePlayer, render]);

  const pressKey = useCallback((key: string) => keysRef.current.add(key), []);
  const releaseKey = useCallback((key: string) => keysRef.current.delete(key), []);

  const formatTime = (s: number) => `${Math.floor(s / 60).toString().padStart(2, "0")}:${(s % 60).toString().padStart(2, "0")}`;

  return (
    <div className="flex flex-col items-center gap-2 select-none">
      <div className="flex gap-4 text-sm font-mono text-white bg-gray-900 px-4 py-1 rounded-full">
        <span>Time: {formatTime(elapsed)}</span>
        {bestTime !== null && <span>Best: {formatTime(bestTime)}</span>}
        <span className="text-yellow-400">Exit: bottom-right</span>
      </div>

      <div className="relative">
        <canvas ref={canvasRef} width={320} height={240} className="border-2 border-gray-600 rounded block" />
        <canvas
          ref={minimapRef}
          width={MAZE_SIZE * MINIMAP_SCALE}
          height={MAZE_SIZE * MINIMAP_SCALE}
          className="absolute top-2 right-2 border border-gray-500 rounded"
          style={{ width: MAZE_SIZE * MINIMAP_SCALE, height: MAZE_SIZE * MINIMAP_SCALE }}
        />
        {won && (
          <div className="absolute inset-0 flex flex-col items-center justify-center bg-black/70 rounded">
            <div className="text-yellow-400 text-2xl font-bold">You Escaped!</div>
            <div className="text-white text-lg mt-1">Time: {formatTime(elapsed)}</div>
            {bestTime !== null && <div className="text-cyan-400 text-sm">Best: {formatTime(bestTime)}</div>}
            <button onClick={resetGame} className="mt-3 px-4 py-2 bg-blue-600 text-white rounded hover:bg-blue-700 font-bold">
              New Maze
            </button>
          </div>
        )}
      </div>

      <div className="flex flex-col items-center gap-1 mt-1">
        <button
          onPointerDown={() => pressKey("w")}
          onPointerUp={() => releaseKey("w")}
          onPointerLeave={() => releaseKey("w")}
          className="w-12 h-10 bg-gray-700 text-white rounded text-sm font-bold hover:bg-gray-600 active:bg-gray-500"
        >W</button>
        <div className="flex gap-1">
          <button onPointerDown={() => pressKey("a")} onPointerUp={() => releaseKey("a")} onPointerLeave={() => releaseKey("a")}
            className="w-12 h-10 bg-gray-700 text-white rounded text-sm font-bold hover:bg-gray-600 active:bg-gray-500">A</button>
          <button onPointerDown={() => pressKey("s")} onPointerUp={() => releaseKey("s")} onPointerLeave={() => releaseKey("s")}
            className="w-12 h-10 bg-gray-700 text-white rounded text-sm font-bold hover:bg-gray-600 active:bg-gray-500">S</button>
          <button onPointerDown={() => pressKey("d")} onPointerUp={() => releaseKey("d")} onPointerLeave={() => releaseKey("d")}
            className="w-12 h-10 bg-gray-700 text-white rounded text-sm font-bold hover:bg-gray-600 active:bg-gray-500">D</button>
        </div>
        <div className="flex gap-2 mt-1">
          <button onPointerDown={() => pressKey("ArrowLeft")} onPointerUp={() => releaseKey("ArrowLeft")} onPointerLeave={() => releaseKey("ArrowLeft")}
            className="w-10 h-10 bg-gray-700 text-white rounded text-sm font-bold hover:bg-gray-600">&#8592;</button>
          <button onPointerDown={() => pressKey("ArrowRight")} onPointerUp={() => releaseKey("ArrowRight")} onPointerLeave={() => releaseKey("ArrowRight")}
            className="w-10 h-10 bg-gray-700 text-white rounded text-sm font-bold hover:bg-gray-600">&#8594;</button>
