        {/* Fullscreen Toggle */}
        {!isFullscreen && (
          <Button
            variant="ghost"
            size="icon"
            className="absolute top-2 right-2 z-10 text-white/50 hover:text-white hover:bg-white/10"
            onClick={toggleFullscreen}
