import { useState, useEffect } from "react";
import { Button } from "@/components/ui/button";
import { Card } from "@/components/ui/card";
import { RefreshCw, Play, Pause, Zap } from "lucide-react";
import confetti from "canvas-confetti";

type Difficulty = "EASY" | "MEDIUM" | "HARD";

// 9x9 grid
const GRID_SIZE = 9;

function generateEmptyBoard() {
    return Array(GRID_SIZE).fill(null).map(() => Array(GRID_SIZE).fill(0));
}

// Simple validator for a row, col, box
function isValid(board: number[][], row: number, col: number, num: number) {
    for (let x = 0; x < GRID_SIZE; x++) {
        if (board[row][x] === num) return false;
    }
    for (let x = 0; x < GRID_SIZE; x++) {
        if (board[x][col] === num) return false;
    }
    let startRow = row - (row % 3), startCol = col - (col % 3);
    for (let i = 0; i < 3; i++) {
        for (let j = 0; j < 3; j++) {
            if (board[i + startRow][j + startCol] === num) return false;
        }
    }
    return true;
}

// Very basic Sudoku generator
function generateSudoku(emptyCount: number) {
    let board = generateEmptyBoard();

    function fillDiagonal() {
        for (let i = 0; i < 9; i = i + 3) fillBox(i, i);
    }

    function fillBox(rowStart: number, colStart: number) {
        let num;
        for (let i = 0; i < 3; i++) {
            for (let j = 0; j < 3; j++) {
                do {
                    num = Math.floor(Math.random() * 9) + 1;
                } while (!isSafeForBox(rowStart, colStart, num));
                board[rowStart + i][colStart + j] = num;
            }
        }
    }

    function isSafeForBox(rowStart: number, colStart: number, num: number) {
        for (let i = 0; i < 3; i++) {
            for (let j = 0; j < 3; j++) {
                if (board[rowStart + i][colStart + j] === num) return false;
            }
        }
        return true;
    }

    function fillRemaining(i: number, j: number): boolean {
        if (j >= 9 && i < 8) {
            i = i + 1;
            j = 0;
        }
        if (i >= 9 && j >= 9) return true;
        if (i < 3) {
            if (j < 3) j = 3;
        } else if (i < 6) {
            if (j === Math.floor(i / 3) * 3) j = j + 3;
        } else {
            if (j === 6) {
                i = i + 1;
                j = 0;
                if (i >= 9) return true;
            }
        }
        for (let num = 1; num <= 9; num++) {
            if (isValid(board, i, j, num)) {
                board[i][j] = num;
                if (fillRemaining(i, j + 1)) return true;
                board[i][j] = 0;
            }
        }
        return false;
    }

    fillDiagonal();
    fillRemaining(0, 3);

    // Clone complete board
    const solution = board.map(row => [...row]);

    // Remove elements
    for (let i = 0; i < emptyCount; i++) {
        let row = Math.floor(Math.random() * 9);
        let col = Math.floor(Math.random() * 9);
        while (board[row][col] === 0) {
            row = Math.floor(Math.random() * 9);
            col = Math.floor(Math.random() * 9);
        }
        board[row][col] = 0;
    }

    return { puzzle: board, solution };
}

export default function SudokuZenGame() {
    const [difficulty, setDifficulty] = useState<Difficulty>("EASY");
    const [board, setBoard] = useState<number[][]>(generateEmptyBoard());
    const [initialBoard, setInitialBoard] = useState<number[][]>(generateEmptyBoard());
    const [solutionBoard, setSolutionBoard] = useState<number[][]>(generateEmptyBoard());
    const [selectedCell, setSelectedCell] = useState<[number, number] | null>(null);
    const [isPlaying, setIsPlaying] = useState(false);
    const [isWon, setIsWon] = useState(false);

    // Time state
    const [time, setTime] = useState(0);

    useEffect(() => {
        let timer: any = null;
        if (isPlaying && !isWon) {
            timer = setInterval(() => setTime((t) => t + 1), 1000);
        }
        return () => clearInterval(timer);
    }, [isPlaying, isWon]);

    const startNewGame = (diff = difficulty) => {
        const emptyCount = diff === "EASY" ? 20 : diff === "MEDIUM" ? 40 : 55;
        const { puzzle, solution } = generateSudoku(emptyCount);
        setBoard(puzzle.map(row => [...row]));
        setInitialBoard(puzzle.map(row => [...row]));
        setSolutionBoard(solution);
        setSelectedCell(null);
        setIsPlaying(true);
        setIsWon(false);
        setTime(0);
        setDifficulty(diff);
    };

    const handleCellClick = (r: number, c: number) => {
        if (!isPlaying || isWon) return;
        setSelectedCell([r, c]);
    };

    const handleNumberInput = (num: number) => {
        if (!isPlaying || !selectedCell || isWon) return;
        const [r, c] = selectedCell;

        if (initialBoard[r][c] !== 0) return; // Cannot overwrite initial numbers

        const newBoard = board.map(row => [...row]);
        newBoard[r][c] = num;
        setBoard(newBoard);

        // Check win condition
        const isComplete = newBoard.every(row => row.every(cell => cell !== 0));
        if (isComplete) {
            const isValidBoard = newBoard.every((row, i) => row.every((val, j) => val === solutionBoard[i][j]));
            if (isValidBoard) {
                setIsWon(true);
                confetti({
                    particleCount: 150,
                    spread: 80,
                    origin: { y: 0.6 }
                });
            }
        }
    };

    useEffect(() => {
        const handleKeyDown = (e: KeyboardEvent) => {
            if (e.key >= '1' && e.key <= '9') {
                handleNumberInput(parseInt(e.key));
            } else if (e.key === 'Backspace' || e.key === 'Delete') {
                handleNumberInput(0);
            }
        };
        window.addEventListener("keydown", handleKeyDown);
        return () => window.removeEventListener("keydown", handleKeyDown);
    }, [selectedCell, isPlaying, isWon, board]);

    return (
        <div className="flex flex-col items-center justify-center w-full max-w-xl mx-auto p-2 sm:p-4 min-h-[500px]">
            {!isPlaying ? (
                <Card className="p-8 w-full max-w-sm flex flex-col items-center text-center shadow-lg border-2">
                    <Zap className="w-16 h-16 text-indigo-500 mb-4 animate-pulse" />
                    <h2 className="text-3xl font-black mb-2 text-slate-800 dark:text-slate-100">Sudoku Zen</h2>
                    <p className="text-slate-500 mb-8 font-medium">Clear your mind. Solve the grid.</p>

                    <div className="w-full flex flex-col gap-3">
                        <Button size="lg" onClick={() => startNewGame("EASY")} className="bg-emerald-500 hover:bg-emerald-600">Easy</Button>
                        <Button size="lg" onClick={() => startNewGame("MEDIUM")} className="bg-amber-500 hover:bg-amber-600">Medium</Button>
                        <Button size="lg" onClick={() => startNewGame("HARD")} className="bg-rose-500 hover:bg-rose-600">Hard</Button>
                    </div>
                </Card>
            ) : (
                <div className="flex flex-col items-center w-full animate-in fade-in duration-500">
                    {/* Header */}
                    <div className="flex w-full items-center justify-between mb-4 px-2">
                        <div className="flex items-center gap-4">
                            <span className="text-xl font-bold font-mono tracking-widest">{Math.floor(time / 60).toString().padStart(2, '0')}:{(time % 60).toString().padStart(2, '0')}</span>
                            <span className="text-sm font-semibold uppercase tracking-wider text-slate-400 border border-slate-200 dark:border-slate-800 rounded-full px-3 py-1">{difficulty}</span>
                        </div>
                        <Button variant="ghost" size="icon" onClick={() => setIsPlaying(false)}>
                            <Pause className="w-5 h-5" />
                        </Button>
                    </div>

                    {/* Board */}
                    <Card className="p-1 sm:p-2 bg-slate-200 dark:bg-slate-800 drop-shadow-xl relative w-full aspect-square max-h-[500px]">
                        {isWon && (
                            <div className="absolute inset-0 z-10 bg-white/90 dark:bg-slate-950/90 backdrop-blur-sm flex flex-col items-center justify-center rounded-xl p-4 text-center">
                                <h3 className="text-4xl font-black text-emerald-600 mb-4 tracking-tight">Completed!</h3>
                                <p className="text-slate-600 dark:text-slate-400 mb-6 font-medium">You solved the {difficulty} puzzle in {Math.floor(time / 60)}m {time % 60}s.</p>
                                <Button onClick={() => setIsPlaying(false)} className="gap-2">
                                    <RefreshCw className="w-4 h-4" /> Next Puzzle
                                </Button>
                            </div>
                        )}

                        <div className="grid grid-cols-9 h-full w-full border-4 border-slate-800 dark:border-slate-200 rounded-lg overflow-hidden gap-[1px] bg-slate-800 dark:bg-slate-200">
                            {board.map((row, r) => (
                                row.map((cell, c) => {
                                    const isSelected = selectedCell?.[0] === r && selectedCell?.[1] === c;
                                    const isGiven = initialBoard[r][c] !== 0;
                                    const isError = !isGiven && cell !== 0 && cell !== solutionBoard[r][c];
                                    // Same number highlighting
                                    const isSameNumber = cell !== 0 && selectedCell && board[selectedCell[0]][selectedCell[1]] === cell;

                                    const rightBorder = (c % 3 === 2 && c !== 8) ? "border-r-2 border-r-slate-800 dark:border-r-slate-200" : "";
                                    const bottomBorder = (r % 3 === 2 && r !== 8) ? "border-b-2 border-b-slate-800 dark:border-b-slate-200" : "";

                                    return (
                                        <div
                                            key={`${r}-${c}`}
                                            onClick={() => handleCellClick(r, c)}
                                            className={`
                          flex items-center justify-center text-lg sm:text-2xl font-semibold cursor-pointer select-none transition-colors
                          ${rightBorder} ${bottomBorder}
                          ${isSelected ? "bg-indigo-200 dark:bg-indigo-900" : isSameNumber ? "bg-indigo-100 dark:bg-indigo-950/50" : "bg-white dark:bg-slate-900"}
                          ${isGiven ? "text-slate-800 dark:text-slate-100 font-black" : "text-indigo-600 dark:text-indigo-400"}
                          ${isError ? "text-rose-500 bg-rose-50 dark:bg-rose-950/30" : ""}
                          hover:bg-slate-50 dark:hover:bg-slate-800
                        `}
                                        >
                                            {cell !== 0 ? cell : ""}
                                        </div>
                                    )
                                })
                            ))}
                        </div>
                    </Card>

                    {/* Number Pad for Mobile */}
                    <div className="grid grid-cols-5 gap-2 w-full mt-6">
                        {[1, 2, 3, 4, 5, 6, 7, 8, 9].map((num) => (
                            <Button
                                key={num}
                                variant="outline"
                                className="h-12 text-xl font-bold rounded-xl active:scale-95 border-2 shadow-sm"
                                onClick={() => handleNumberInput(num)}
                            >
                                {num}
                            </Button>
                        ))}
                        <Button
                            variant="outline"
                            className="h-12 text-sm font-bold rounded-xl text-rose-500 active:scale-95 border-2 col-start-5 border-rose-200"
                            onClick={() => handleNumberInput(0)}
                        >
                            DEL
                        </Button>
                    </div>
                </div>
            )}
        </div>
    );
}

import React, { useState, useEffect, useRef, useCallback } from "react";
import CalculatorVerticalLayout from "@/components/templates/CalculatorVerticalLayout";

// ΓöÇΓöÇΓöÇ Constants ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
const W = 700;
const H = 420;
const TABLE_TOP = H / 2 - 80;
const TABLE_BOTTOM = H / 2 + 80;
const TABLE_LEFT = 80;
const TABLE_RIGHT = W - 80;
const TABLE_MID_X = W / 2;
const NET_H = 40;
const NET_TOP = TABLE_TOP - NET_H / 2;
const PADDLE_W = 12;
const PADDLE_H = 70;
const BALL_R = 8;
const PLAYER_X = TABLE_LEFT + 20;
const AI_X = TABLE_RIGHT - 20;
const WINNING_SCORE = 11;
const SETS_TO_WIN = 2;

// AI difficulty: track factor 0..1 (1=perfect tracking)
const AI_TRACK = 0.08;

interface Ball {
  x: number; y: number;
  vx: number; vy: number;
  spin: number; // affects bounce angle
  bounced: boolean; // hit table this side
}

interface GameState {
  phase: "menu" | "playing" | "point" | "setover" | "gameover";
  playerY: number;
  aiY: number;
  ball: Ball;
  playerScore: number;
  aiScore: number;
  playerSets: number;
  aiSets: number;
  lastScorer: "player" | "ai" | null;
  pointText: string;
  pointTimer: number;
  frameCount: number;
  serving: "player" | "ai";
  rallying: boolean;
  particles: { x: number; y: number; vx: number; vy: number; life: number; color: string }[];
  touchY: number;
}

function initBall(serving: "player" | "ai"): Ball {
  const dir = serving === "player" ? 1 : -1;
  return {
    x: serving === "player" ? PLAYER_X + 30 : AI_X - 30,
    y: (TABLE_TOP + TABLE_BOTTOM) / 2,
    vx: dir * 6,
    vy: (Math.random() - 0.5) * 3,
    spin: 0,
    bounced: false,
  };
}

function initState(): GameState {
  return {
    phase: "menu",
    playerY: H / 2,
    aiY: H / 2,
    ball: initBall("player"),
    playerScore: 0, aiScore: 0,
    playerSets: 0, aiSets: 0,
    lastScorer: null,
    pointText: "",
    pointTimer: 0,
    frameCount: 0,
    serving: "player",
    rallying: false,
    particles: [],
    touchY: H / 2,
  };
}

// ΓöÇΓöÇΓöÇ Game UI ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
function GameUI() {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const stateRef = useRef<GameState>(initState());
  const animRef = useRef<number>(0);
  const [uiState, setUiState] = useState({ playerScore: 0, aiScore: 0, playerSets: 0, aiSets: 0, phase: "menu" as string });
  const winsRef = useRef(parseInt(localStorage.getItem("hs_table-tennis-pro") || "0"));
  const [wins, setWins] = useState(winsRef.current);

  const startGame = useCallback(() => {
    const s = initState();
    s.phase = "playing";
    s.ball = initBall("player");
    stateRef.current = s;
  }, []);

  const awardPoint = useCallback((scorer: "player" | "ai") => {
    const s = stateRef.current;
    if (scorer === "player") {
      s.playerScore++;
      s.pointText = "Your Point!";
    } else {
      s.aiScore++;
      s.pointText = "AI Point!";
    }
    s.lastScorer = scorer;

    // Particles
    const px = scorer === "player" ? PLAYER_X : AI_X;
    for (let i = 0; i < 15; i++) {
      s.particles.push({
        x: s.ball.x, y: s.ball.y,
        vx: (Math.random() - 0.5) * 10,
        vy: (Math.random() - 0.5) * 10,
        life: 1,
        color: scorer === "player" ? "#3498db" : "#e74c3c",
      });
    }

    // Check set win (first to 11, must lead by 2 if deuce)
    const ps = s.playerScore;
    const as = s.aiScore;
    const setOver = (ps >= WINNING_SCORE || as >= WINNING_SCORE) && Math.abs(ps - as) >= 2;
    if (setOver) {
      if (ps > as) {
        s.playerSets++;
        s.pointText = "Set to YOU!";
      } else {
        s.aiSets++;
        s.pointText = "Set to AI!";
      }
      s.playerScore = 0; s.aiScore = 0;
      if (s.playerSets >= SETS_TO_WIN || s.aiSets >= SETS_TO_WIN) {
        s.phase = "gameover";
        if (s.playerSets >= SETS_TO_WIN) {
          winsRef.current++;
          try { localStorage.setItem("hs_table-tennis-pro", String(winsRef.current)); } catch {}
          setWins(winsRef.current);
        }
      } else {
        s.phase = "setover";
      }
    } else {
      s.phase = "point";
    }

    s.pointTimer = 90;
    s.serving = scorer;
    s.ball = initBall(scorer);
    s.rallying = false;
  }, []);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    const handleMouseMove = (e: MouseEvent) => {
      const rect = canvas.getBoundingClientRect();
      stateRef.current.playerY = (e.clientY - rect.top) * (H / rect.height);
    };

    const handleTouchMove = (e: TouchEvent) => {
      e.preventDefault();
      const rect = canvas.getBoundingClientRect();
      stateRef.current.playerY = (e.touches[0].clientY - rect.top) * (H / rect.height);
    };

    canvas.addEventListener("mousemove", handleMouseMove);
    canvas.addEventListener("touchmove", handleTouchMove, { passive: false });
    return () => {
      canvas.removeEventListener("mousemove", handleMouseMove);
      canvas.removeEventListener("touchmove", handleTouchMove);
    };
  }, []);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext("2d")!;

    const loop = () => {
      const s = stateRef.current;
      s.frameCount++;

      if (s.phase === "playing" || s.phase === "point" || s.phase === "setover") {
        // Point resume
        if ((s.phase === "point" || s.phase === "setover") && s.pointTimer > 0) {
          s.pointTimer--;
          if (s.pointTimer <= 0 && s.phase === "point") s.phase = "playing";
          if (s.pointTimer <= 0 && s.phase === "setover") s.phase = "playing";
        }

        // Clamp paddles to table area
        s.playerY = Math.max(TABLE_TOP + PADDLE_H / 2, Math.min(TABLE_BOTTOM - PADDLE_H / 2, s.playerY));

        // AI paddle tracking
        const aiTarget = s.ball.y;
        s.aiY += (aiTarget - s.aiY) * AI_TRACK * (s.rallying ? 1 : 0.5);
        s.aiY = Math.max(TABLE_TOP + PADDLE_H / 2, Math.min(TABLE_BOTTOM - PADDLE_H / 2, s.aiY));

        // Ball physics
        if (s.phase === "playing") {
          s.ball.x += s.ball.vx;
          s.ball.y += s.ball.vy + s.ball.spin * 0.05;

          // Apply gravity-like drift
          const tableMid = (TABLE_TOP + TABLE_BOTTOM) / 2;
          if (s.ball.y < TABLE_TOP || s.ball.y > TABLE_BOTTOM) {
            s.ball.vy += 0.15; // gravity when not on table
          }

          // Bounce off table top/bottom edges
          if (s.ball.y - BALL_R < TABLE_TOP) {
            s.ball.y = TABLE_TOP + BALL_R;
            s.ball.vy = Math.abs(s.ball.vy) * 0.85;
            s.ball.spin *= 0.9;
          }
          if (s.ball.y + BALL_R > TABLE_BOTTOM) {
            s.ball.y = TABLE_BOTTOM - BALL_R;
            s.ball.vy = -Math.abs(s.ball.vy) * 0.85;
            s.ball.spin *= 0.9;
          }

          // Net collision
          if (Math.abs(s.ball.x - TABLE_MID_X) < BALL_R) {
            if (s.ball.y > TABLE_TOP - NET_H / 2 && s.ball.y < TABLE_TOP) {
              // Ball hits net
              s.ball.vx *= -0.7;
              s.ball.vy *= 0.8;
            }
          }

          // Player paddle collision
          const playerPaddleTop = s.playerY - PADDLE_H / 2;
          const playerPaddleBot = s.playerY + PADDLE_H / 2;
          if (
            s.ball.x - BALL_R <= PLAYER_X + PADDLE_W &&
            s.ball.x - BALL_R >= PLAYER_X - PADDLE_W &&
            s.ball.y >= playerPaddleTop &&
            s.ball.y <= playerPaddleBot &&
            s.ball.vx < 0
          ) {
            const relHit = (s.ball.y - s.playerY) / (PADDLE_H / 2); // -1..1
            s.ball.vx = Math.abs(s.ball.vx) * 1.05 + 0.5;
            s.ball.vy = relHit * 6;
            s.ball.spin = relHit * 2;
            s.ball.x = PLAYER_X + PADDLE_W + BALL_R;
            s.rallying = true;
            // Clamp max speed
            s.ball.vx = Math.min(s.ball.vx, 14);
          }

          // AI paddle collision
          const aiPaddleTop = s.aiY - PADDLE_H / 2;
          const aiPaddleBot = s.aiY + PADDLE_H / 2;
          if (
            s.ball.x + BALL_R >= AI_X - PADDLE_W &&
            s.ball.x + BALL_R <= AI_X + PADDLE_W &&
            s.ball.y >= aiPaddleTop &&
            s.ball.y <= aiPaddleBot &&
            s.ball.vx > 0
          ) {
            const relHit = (s.ball.y - s.aiY) / (PADDLE_H / 2);
            s.ball.vx = -(Math.abs(s.ball.vx) * 1.03 + 0.5);
            s.ball.vy = relHit * 5;
            s.ball.spin = -relHit * 1.5;
            s.ball.x = AI_X - PADDLE_W - BALL_R;
            s.rallying = true;
            s.ball.vx = Math.max(s.ball.vx, -14);
          }

          // Ball goes off left (AI scores)
          if (s.ball.x + BALL_R < TABLE_LEFT - 30) {
            awardPoint("ai");
          }
          // Ball goes off right (Player scores)
          if (s.ball.x - BALL_R > TABLE_RIGHT + 30) {
            awardPoint("player");
          }
          // Ball goes way off top/bottom = fault (serving player loses point)
          if (s.ball.y < 0 || s.ball.y > H) {
            awardPoint(s.ball.vx > 0 ? "ai" : "player");
          }
        }

        // Particles
        s.particles.forEach((p) => { p.x += p.vx; p.y += p.vy; p.vy += 0.2; p.life -= 0.04; });
        s.particles = s.particles.filter((p) => p.life > 0);
      }

      // ΓöÇΓöÇΓöÇ Draw ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
      // Background
      const bg = ctx.createLinearGradient(0, 0, 0, H);
      bg.addColorStop(0, "#1a1a3e");
      bg.addColorStop(1, "#0d0d1f");
      ctx.fillStyle = bg;
      ctx.fillRect(0, 0, W, H);

      // Table surface
      const tableGrad = ctx.createLinearGradient(0, TABLE_TOP, 0, TABLE_BOTTOM);
      tableGrad.addColorStop(0, "#1565c0");
      tableGrad.addColorStop(0.5, "#1976d2");
      tableGrad.addColorStop(1, "#1565c0");
      ctx.fillStyle = tableGrad;
      ctx.fillRect(TABLE_LEFT, TABLE_TOP, TABLE_RIGHT - TABLE_LEFT, TABLE_BOTTOM - TABLE_TOP);

      // Table edges
      ctx.strokeStyle = "#fff";
      ctx.lineWidth = 3;
      ctx.strokeRect(TABLE_LEFT, TABLE_TOP, TABLE_RIGHT - TABLE_LEFT, TABLE_BOTTOM - TABLE_TOP);

      // Center line
      ctx.strokeStyle = "rgba(255,255,255,0.5)";
      ctx.lineWidth = 2;
      ctx.setLineDash([8, 8]);
      ctx.beginPath();
      ctx.moveTo(TABLE_MID_X, TABLE_TOP);
      ctx.lineTo(TABLE_MID_X, TABLE_BOTTOM);
      ctx.stroke();
      ctx.setLineDash([]);

      // Table legs
      ctx.fillStyle = "#333";
      [[TABLE_LEFT, TABLE_BOTTOM], [TABLE_RIGHT - 10, TABLE_BOTTOM], [TABLE_LEFT, TABLE_TOP - 10], [TABLE_RIGHT - 10, TABLE_TOP - 10]].forEach(([x, y]) => {
        ctx.fillRect(x, y, 10, 30);
      });

      // Net
      ctx.fillStyle = "#aaa";
      ctx.fillRect(TABLE_MID_X - 3, NET_TOP, 6, NET_H);
      ctx.fillStyle = "#fff";
      ctx.fillRect(TABLE_MID_X - 5, NET_TOP - 5, 10, 8);
      ctx.fillRect(TABLE_MID_X - 5, NET_TOP + NET_H - 5, 10, 8);

      // Floor shadow under table
      ctx.fillStyle = "rgba(0,0,0,0.3)";
      ctx.beginPath();
      ctx.ellipse(W / 2, TABLE_BOTTOM + 25, (TABLE_RIGHT - TABLE_LEFT) / 2.2, 12, 0, 0, Math.PI * 2);
      ctx.fill();

      // Player paddle
      const drawPaddle = (x: number, y: number, color: string, label: string) => {
        const t = y - PADDLE_H / 2;
        ctx.fillStyle = color;
        ctx.beginPath();
        ctx.roundRect(x - PADDLE_W / 2, t, PADDLE_W, PADDLE_H, 4);
        ctx.fill();
        ctx.strokeStyle = "rgba(255,255,255,0.3)";
        ctx.lineWidth = 1;
        ctx.stroke();
        // Handle
        ctx.fillStyle = "#8d4f1e";
        ctx.fillRect(x - 4, t + PADDLE_H, 8, 20);
        ctx.fillStyle = "rgba(255,255,255,0.8)";
        ctx.font = "10px sans-serif";
        ctx.textAlign = "center";
        ctx.fillText(label, x, t - 6);
        ctx.textAlign = "left";
      };
      drawPaddle(PLAYER_X, stateRef.current.playerY, "#3498db", "YOU");
      drawPaddle(AI_X, stateRef.current.aiY, "#e74c3c", "AI");

      // Draw ball with shadow
      ctx.beginPath();
      ctx.arc(stateRef.current.ball.x + 3, stateRef.current.ball.y + 3, BALL_R, 0, Math.PI * 2);
      ctx.fillStyle = "rgba(0,0,0,0.3)";
      ctx.fill();
      const ballGrad = ctx.createRadialGradient(
        stateRef.current.ball.x - 2, stateRef.current.ball.y - 2, 1,
        stateRef.current.ball.x, stateRef.current.ball.y, BALL_R
      );
      ballGrad.addColorStop(0, "#fffde7");
      ballGrad.addColorStop(0.7, "#fff9c4");
      ballGrad.addColorStop(1, "#f9a825");
      ctx.beginPath();
      ctx.arc(stateRef.current.ball.x, stateRef.current.ball.y, BALL_R, 0, Math.PI * 2);
      ctx.fillStyle = ballGrad;
      ctx.fill();

      // Spin indicator
      if (Math.abs(stateRef.current.ball.spin) > 0.3) {
        ctx.strokeStyle = stateRef.current.ball.spin > 0 ? "#ff6b6b" : "#69b7fb";
        ctx.lineWidth = 1.5;
        ctx.beginPath();
        ctx.arc(stateRef.current.ball.x, stateRef.current.ball.y, BALL_R + 4, 0, Math.PI * Math.abs(stateRef.current.ball.spin));
        ctx.stroke();
      }

      // Particles
      for (const p of stateRef.current.particles) {
        ctx.beginPath();
        ctx.arc(p.x, p.y, 4 * p.life, 0, Math.PI * 2);
        ctx.fillStyle = p.color;
        ctx.globalAlpha = p.life;
        ctx.fill();
        ctx.globalAlpha = 1;
      }

      // Score display
      ctx.fillStyle = "rgba(0,0,0,0.55)";
      ctx.fillRect(0, 0, W, 52);
      ctx.fillStyle = "#3498db";
      ctx.font = "bold 28px sans-serif";
      ctx.textAlign = "left";
      ctx.fillText(`${stateRef.current.playerScore}`, TABLE_LEFT + 20, 36);
      ctx.fillStyle = "#e74c3c";
      ctx.textAlign = "right";
      ctx.fillText(`${stateRef.current.aiScore}`, W - TABLE_LEFT - 20, 36);
      ctx.fillStyle = "#fff";
      ctx.font = "13px sans-serif";
      ctx.textAlign = "center";
      ctx.fillText(`Sets: YOU ${stateRef.current.playerSets} ΓÇö ${stateRef.current.aiSets} AI`, W / 2, 22);
      ctx.font = "18px sans-serif";
      ctx.fillText(`${stateRef.current.playerScore} : ${stateRef.current.aiScore}`, W / 2, 40);

      // Point text
      if ((stateRef.current.phase === "point" || stateRef.current.phase === "setover") && stateRef.current.pointText) {
        ctx.fillStyle = stateRef.current.lastScorer === "player" ? "#3498db" : "#e74c3c";
        ctx.font = "bold 38px sans-serif";
        ctx.textAlign = "center";
        ctx.shadowColor = "#000";
        ctx.shadowBlur = 12;
        ctx.fillText(stateRef.current.pointText, W / 2, H / 2 + 10);
        ctx.shadowBlur = 0;
      }
      ctx.textAlign = "left";

      // Serving indicator
      if (stateRef.current.phase === "playing" && !stateRef.current.rallying) {
        ctx.fillStyle = "#ffd700";
        ctx.font = "13px sans-serif";
        ctx.textAlign = "center";
        ctx.fillText(stateRef.current.serving === "player" ? "Your serve ΓåÆ" : "ΓåÉ AI serve", W / 2, H - 10);
        ctx.textAlign = "left";
      }

      // Overlays
      if (s.phase === "menu") {
        ctx.fillStyle = "rgba(0,0,0,0.82)";
        ctx.fillRect(0, 0, W, H);
        ctx.fillStyle = "#3498db";
        ctx.font = "bold 22px sans-serif";
        ctx.textAlign = "center";
        ctx.fillText("TABLE TENNIS PRO", W / 2, H / 2 - 90);
        ctx.fillStyle = "#fff";
        ctx.font = "bold 58px sans-serif";
        ctx.fillText("≡ƒÅô", W / 2, H / 2 - 30);
        ctx.fillStyle = "#aaa";
        ctx.font = "16px sans-serif";
        ctx.fillText("Move mouse up/down to control your paddle (left)", W / 2, H / 2 + 30);
        ctx.fillText(`First to ${WINNING_SCORE} points wins a set. Best of ${SETS_TO_WIN * 2 - 1} sets.`, W / 2, H / 2 + 55);
        ctx.fillStyle = "#2ecc71";
        ctx.font = "bold 22px sans-serif";
        ctx.fillText("Click / Tap to Start", W / 2, H / 2 + 100);
        ctx.textAlign = "left";
      } else if (s.phase === "gameover") {
        ctx.fillStyle = "rgba(0,0,0,0.82)";
        ctx.fillRect(0, 0, W, H);
        const youWin = s.playerSets > s.aiSets;
        ctx.fillStyle = youWin ? "#3498db" : "#e74c3c";
        ctx.font = "bold 54px sans-serif";
        ctx.textAlign = "center";
        ctx.fillText(youWin ? "YOU WIN!" : "AI WINS!", W / 2, H / 2 - 30);
        ctx.fillStyle = "#fff";
        ctx.font = "26px sans-serif";
        ctx.fillText(`Sets: ${s.playerSets} ΓÇö ${s.aiSets}`, W / 2, H / 2 + 25);
        ctx.fillStyle = "#aaa";
        ctx.font = "18px sans-serif";
        ctx.fillText("Click to play again", W / 2, H / 2 + 70);
        ctx.textAlign = "left";
      }

      setUiState({ playerScore: s.playerScore, aiScore: s.aiScore, playerSets: s.playerSets, aiSets: s.aiSets, phase: s.phase });
      animRef.current = requestAnimationFrame(loop);
    };

    animRef.current = requestAnimationFrame(loop);
    return () => cancelAnimationFrame(animRef.current);
  }, [awardPoint]);

  const handleClick = useCallback(() => {
    const s = stateRef.current;
    if (s.phase === "menu" || s.phase === "gameover") startGame();
  }, [startGame]);

  return (
    <div className="flex flex-col items-center gap-3 select-none">
      <div className="flex gap-6 text-sm font-bold">
        <span className="text-blue-400">YOU: {uiState.playerScore} (Sets: {uiState.playerSets})</span>
        <span className="text-red-400">AI: {uiState.aiScore} (Sets: {uiState.aiSets})</span>
        <span className="text-purple-400">Wins: {wins}</span>
      </div>
      <canvas
        ref={canvasRef}
        width={W}
        height={H}
        onClick={handleClick}
        style={{ maxWidth: "100%", borderRadius: "12px", cursor: "none", touchAction: "none" }}
      />
      <p className="text-xs text-gray-400">Move mouse up/down to control paddle ΓÇó First to 11 wins a set ΓÇó Best of 3 sets</p>
    </div>
  );
}

