import { useState, useEffect } from "react";
import { Button } from "@/components/ui/button";
import { Card } from "@/components/ui/card";
import { RefreshCw, Trophy } from "lucide-react";

const WORDS = [
    "REACT", "APPLE", "BRAIN", "CLOUD", "DREAM", "EAGLE", "FLAME", "GHOST", "HEART", "IMAGE",
    "JUICE", "KNIFE", "LEMON", "MAGIC", "NIGHT", "OCEAN", "PEACE", "QUEEN", "RIVER", "SNAKE",
    "TRAIN", "UNION", "VOICE", "WATER", "XENON", "YACHT", "ZEBRA", "SMART", "WORLD", "LIGHT"
];

const MAX_GUESSES = 6;
const WORD_LENGTH = 5;

type LetterState = "CORRECT" | "PRESENT" | "ABSENT" | "EMPTY";

interface Guess {
    word: string;
    states: LetterState[];
}

export default function WordleUnlimitedGame() {
    const [targetWord, setTargetWord] = useState("");
    const [guesses, setGuesses] = useState<Guess[]>([]);
    const [currentGuess, setCurrentGuess] = useState("");
    const [gameStatus, setGameStatus] = useState<"PLAYING" | "WON" | "LOST">("PLAYING");

    const initGame = () => {
        const randomWord = WORDS[Math.floor(Math.random() * WORDS.length)];
        setTargetWord(randomWord);
        setGuesses([]);
        setCurrentGuess("");
        setGameStatus("PLAYING");
    };

    useEffect(() => {
        initGame();
    }, []);

    const evaluateGuess = (guess: string): LetterState[] => {
        const states: LetterState[] = Array(WORD_LENGTH).fill("ABSENT");
        const targetChars = targetWord.split("");
        const guessChars = guess.split("");

        // First pass: Find CORRECT letters
        guessChars.forEach((char, i) => {
            if (char === targetChars[i]) {
                states[i] = "CORRECT";
                targetChars[i] = null as any; // Mark as used
            }
        });

        // Second pass: Find PRESENT letters
        guessChars.forEach((char, i) => {
            if (states[i] !== "CORRECT" && targetChars.includes(char)) {
                states[i] = "PRESENT";
                targetChars[targetChars.indexOf(char)] = null as any; // Mark as used
            }
        });

        return states;
    };

    const handleKeyPress = (key: string) => {
        if (gameStatus !== "PLAYING") return;

        if (key === "ENTER") {
            if (currentGuess.length === WORD_LENGTH) {
                const states = evaluateGuess(currentGuess);
                const newGuess = { word: currentGuess, states };
                const newGuesses = [...guesses, newGuess];
                setGuesses(newGuesses);
                setCurrentGuess("");

                if (currentGuess === targetWord) {
                    setGameStatus("WON");
                } else if (newGuesses.length >= MAX_GUESSES) {
                    setGameStatus("LOST");
                }
            }
        } else if (key === "BACKSPACE" || key === "DELETE") {
            setCurrentGuess((prev) => prev.slice(0, -1));
        } else if (/^[A-Z]$/.test(key) && currentGuess.length < WORD_LENGTH) {
            setCurrentGuess((prev) => prev + key);
        }
    };

    useEffect(() => {
        const handleKeyDown = (e: KeyboardEvent) => {
            const key = e.key.toUpperCase();
            if (key === "ENTER" || key === "BACKSPACE" || key === "DELETE" || /^[A-Z]$/.test(key)) {
                handleKeyPress(key);
            }
        };
        window.addEventListener("keydown", handleKeyDown);
        return () => window.removeEventListener("keydown", handleKeyDown);
    }, [currentGuess, gameStatus, targetWord]);

    // Keyboard layout
    const keyboardRows = [
        ["Q", "W", "E", "R", "T", "Y", "U", "I", "O", "P"],
        ["A", "S", "D", "F", "G", "H", "J", "K", "L"],
        ["ENTER", "Z", "X", "C", "V", "B", "N", "M", "BACKSPACE"],
    ];

    // Helper to find letter state for keyboard coloring
    const getLetterState = (letter: string) => {
        let state: LetterState = "EMPTY";
        for (const guess of guesses) {
            for (let i = 0; i < WORD_LENGTH; i++) {
                if (guess.word[i] === letter) {
                    if (guess.states[i] === "CORRECT") return "CORRECT";
                    if (guess.states[i] === "PRESENT") state = "PRESENT";
                    if (guess.states[i] === "ABSENT" && state === "EMPTY") state = "ABSENT";
                }
            }
        }
        return state;
    };

    return (
        <div className="flex flex-col items-center w-full max-w-md mx-auto p-4 select-none touch-manipulation">
            {/* Game Header */}
            <div className="w-full flex justify-between items-center mb-6 border-b pb-4 dark:border-slate-800">
                <h2 className="text-3xl font-black tracking-widest text-slate-800 dark:text-slate-100 uppercase">Wordle</h2>
                <Button variant="ghost" size="icon" onClick={initGame} title="Restart Game">
                    <RefreshCw className="w-5 h-5 text-slate-500" />
                </Button>
            </div>

            {/* Grid */}
            <div className="flex flex-col gap-2 w-full max-w-[300px] mb-8">
                {Array.from({ length: MAX_GUESSES }).map((_, rowIndex) => {
                    const guess = guesses[rowIndex];
                    const isCurrentRow = rowIndex === guesses.length;

                    return (
                        <div key={rowIndex} className="grid grid-cols-5 gap-2 w-full">
                            {Array.from({ length: WORD_LENGTH }).map((_, colIndex) => {
                                let letter = "";
                                let state: LetterState = "EMPTY";

                                if (guess) {
                                    letter = guess.word[colIndex];
                                    state = guess.states[colIndex];
                                } else if (isCurrentRow) {
                                    letter = currentGuess[colIndex] || "";
                                }

                                // Tile Styling based on state
                                let stateClasses = "border-slate-300 dark:border-slate-700 bg-white dark:bg-slate-900"; // EMPTY
                                if (state === "CORRECT") stateClasses = "bg-emerald-500 border-emerald-500 text-white shadow-md shadow-emerald-500/20";
                                if (state === "PRESENT") stateClasses = "bg-amber-500 border-amber-500 text-white shadow-md shadow-amber-500/20";
                                if (state === "ABSENT") stateClasses = "bg-slate-500 border-slate-500 text-white dark:bg-slate-700 dark:border-slate-700";

                                const isPopulated = letter !== "" && state === "EMPTY";

                                return (
                                    <div
                                        key={colIndex}
                                        className={`
                      aspect-square flex items-center justify-center text-2xl sm:text-3xl font-bold uppercase transition-all duration-300
                      ${state === "EMPTY" ? 'border-2' : 'border-0'} 
                      ${isPopulated ? 'border-slate-400 dark:border-slate-500 scale-[1.02]' : ''}
                      ${stateClasses} rounded-lg
                    `}
                                    >
                                        {letter}
                                    </div>
                                );
                            })}
                        </div>
                    );
                })}
            </div>

            {/* Game Status Overlay / Message */}
            {gameStatus !== "PLAYING" && (
                <Card className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 p-6 z-10 w-11/12 max-w-sm text-center shadow-2xl animate-in zoom-in duration-300 bg-white/95 dark:bg-slate-900/95 backdrop-blur-md">
                    <Trophy className={`w-16 h-16 mx-auto mb-4 ${gameStatus === "WON" ? "text-emerald-500" : "text-slate-400"}`} />
                    <h3 className="text-3xl font-black mb-2 uppercase tracking-wide">
                        {gameStatus === "WON" ? "You Won!" : "Game Over"}
                    </h3>
                    <p className="text-lg text-slate-600 dark:text-slate-400 mb-6 font-medium">
                        The word was <strong className="text-slate-900 dark:text-white">{targetWord}</strong>.
                    </p>
                    <Button onClick={initGame} className="w-full h-12 text-lg font-bold gap-2">
                        <RefreshCw className="w-5 h-5" /> Play Again
                    </Button>
                </Card>
            )}

            {/* On-screen Keyboard (Mobile friendly) */}
            <div className="w-full max-w-[500px] flex flex-col gap-2 mt-auto">
                {keyboardRows.map((row, rowIndex) => (
                    <div key={rowIndex} className="flex justify-center gap-1 sm:gap-2">
                        {row.map((key) => {
                            const state = getLetterState(key);
                            let keyBg = "bg-slate-200 dark:bg-slate-700 hover:bg-slate-300 dark:hover:bg-slate-600 text-slate-800 dark:text-slate-100";
                            if (state === "CORRECT") keyBg = "bg-emerald-500 text-white";
                            if (state === "PRESENT") keyBg = "bg-amber-500 text-white";
                            if (state === "ABSENT") keyBg = "bg-slate-800 text-white dark:bg-slate-900";

                            const isSpecial = key === "ENTER" || key === "BACKSPACE";

                            return (
                                <button
                                    key={key}
                                    onClick={() => handleKeyPress(key)}
                                    className={`
                    flex-1 flex items-center justify-center font-bold rounded-md shadow-sm active:scale-95 transition-all outline-none
                    ${isSpecial ? "text-xs sm:text-sm px-2 min-w-[3.5rem] sm:min-w-[4.5rem]" : "text-sm sm:text-lg min-w-[2rem] sm:min-w-[2.5rem]"}
                    h-12 sm:h-14 ${keyBg}
                  `}
                                >
                                    {key === "BACKSPACE" ? "DEL" : key}
                                </button>
                            );
                        })}
                    </div>
                ))}
            </div>
        </div>
    );
}

import React, { useState, useEffect, useRef, useCallback } from "react";
import CalculatorVerticalLayout from "@/components/templates/CalculatorVerticalLayout";

// ΓöÇΓöÇΓöÇ Constants ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
const W = 600;
const H = 600;
const MARBLE_R = 14;
const COLORS = ["#e74c3c", "#3498db", "#2ecc71", "#f1c40f"];
const CHAIN_COUNT = 40;
const HOLE_X = W / 2;
const HOLE_Y = H / 2;
const BASE_SPEED = 0.4;

// Bezier path control points for curved path
const PATH_POINTS = [
  { x: W - 30, y: 30 },
  { x: W - 60, y: 150 },
  { x: W - 100, y: 220 },
  { x: W / 2 + 100, y: 160 },
  { x: W / 2 + 180, y: H / 2 - 60 },
  { x: W / 2 + 120, y: H / 2 + 40 },
  { x: W / 2 + 60, y: H / 2 + 20 },
  { x: HOLE_X, y: HOLE_Y },
];

function lerpPoints(points: { x: number; y: number }[], t: number) {
  if (points.length === 1) return points[0];
  const newPoints: { x: number; y: number }[] = [];
  for (let i = 0; i < points.length - 1; i++) {
    newPoints.push({
      x: points[i].x + (points[i + 1].x - points[i].x) * t,
      y: points[i].y + (points[i + 1].y - points[i].y) * t,
    });
  }
  return lerpPoints(newPoints, t);
}

function getPathPos(t: number) {
  return lerpPoints(PATH_POINTS, Math.max(0, Math.min(1, t)));
}

interface Marble {
  t: number; // 0..1 position on path
  color: string;
  id: number;
  popping: boolean;
  popFrame: number;
}

interface FlyingMarble {
  x: number;
  y: number;
  vx: number;
  vy: number;
  color: string;
}

const HS_KEY = "hs_zuma-tumble";

// ΓöÇΓöÇΓöÇ Game UI ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
function GameUI() {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const stateRef = useRef({
    marbles: [] as Marble[],
    flying: null as FlyingMarble | null,
    nextColor: COLORS[Math.floor(Math.random() * COLORS.length)],
    currentColor: COLORS[Math.floor(Math.random() * COLORS.length)],
    angle: 0,
    lives: 3,
    score: 0,
    highScore: parseInt(localStorage.getItem(HS_KEY) || "0"),
    phase: "playing" as "playing" | "gameover" | "win",
    idCounter: 0,
    speed: BASE_SPEED,
    frame: 0,
  });
  const animRef = useRef<number>(0);
  const [display, setDisplay] = useState({ lives: 3, score: 0, highScore: parseInt(localStorage.getItem(HS_KEY) || "0"), phase: "playing" as string, currentColor: COLORS[0], nextColor: COLORS[1] });

  const initChain = useCallback(() => {
    const s = stateRef.current;
    s.marbles = [];
    s.idCounter = 0;
    for (let i = 0; i < CHAIN_COUNT; i++) {
      s.marbles.push({
        t: -(i * (MARBLE_R * 2.2)) / 1200,
        color: COLORS[Math.floor(Math.random() * COLORS.length)],
        id: s.idCounter++,
        popping: false,
        popFrame: 0,
      });
    }
    s.flying = null;
    s.lives = 3;
    s.score = 0;
    s.phase = "playing";
    s.speed = BASE_SPEED;
    s.frame = 0;
    s.highScore = parseInt(localStorage.getItem(HS_KEY) || "0");
  }, []);

  useEffect(() => {
    initChain();
  }, [initChain]);

  const checkMatches = useCallback(() => {
    const s = stateRef.current;
    const alive = s.marbles.filter((m) => !m.popping);
    let changed = true;
    while (changed) {
      changed = false;
      for (let i = 0; i < alive.length - 2; i++) {
        if (alive[i].color === alive[i + 1].color && alive[i].color === alive[i + 2].color) {
          let j = i;
          while (j < alive.length && alive[j].color === alive[i].color) j++;
          const toRemove = alive.splice(i, j - i);
          toRemove.forEach((m) => { m.popping = true; m.popFrame = 0; });
          s.score += toRemove.length * 10;
          changed = true;
          break;
        }
      }
    }
    s.marbles = [...s.marbles.filter((m) => m.popping), ...alive];
  }, []);

  const fireMarble = useCallback((cx: number, cy: number, tx: number, ty: number) => {
    const s = stateRef.current;
    if (s.flying || s.phase !== "playing") return;
    const dx = tx - cx;
    const dy = ty - cy;
    const len = Math.sqrt(dx * dx + dy * dy);
    const speed = 8;
    s.flying = {
      x: cx, y: cy,
      vx: (dx / len) * speed,
      vy: (dy / len) * speed,
      color: s.currentColor,
    };
    s.currentColor = s.nextColor;
    s.nextColor = COLORS[Math.floor(Math.random() * COLORS.length)];
  }, []);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    const handleMouseMove = (e: MouseEvent) => {
      const rect = canvas.getBoundingClientRect();
      const mx = (e.clientX - rect.left) * (W / rect.width);
      const my = (e.clientY - rect.top) * (H / rect.height);
      const dx = mx - HOLE_X;
      const dy = my - HOLE_Y;
      stateRef.current.angle = Math.atan2(dy, dx);
    };

    const handleClick = (e: MouseEvent) => {
      const rect = canvas.getBoundingClientRect();
      const mx = (e.clientX - rect.left) * (W / rect.width);
      const my = (e.clientY - rect.top) * (H / rect.height);
      fireMarble(HOLE_X, HOLE_Y, mx, my);
    };

    const handleTouch = (e: TouchEvent) => {
      e.preventDefault();
      const rect = canvas.getBoundingClientRect();
      const t = e.touches[0];
      const mx = (t.clientX - rect.left) * (W / rect.width);
      const my = (t.clientY - rect.top) * (H / rect.height);
      stateRef.current.angle = Math.atan2(my - HOLE_Y, mx - HOLE_X);
      fireMarble(HOLE_X, HOLE_Y, mx, my);
    };

    canvas.addEventListener("mousemove", handleMouseMove);
    canvas.addEventListener("click", handleClick);
    canvas.addEventListener("touchstart", handleTouch, { passive: false });
    return () => {
      canvas.removeEventListener("mousemove", handleMouseMove);
      canvas.removeEventListener("click", handleClick);
      canvas.removeEventListener("touchstart", handleTouch);
    };
  }, [fireMarble]);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext("2d")!;

    const loop = () => {
      const s = stateRef.current;
      s.frame++;

      if (s.phase === "playing") {
        // Move chain
        s.speed = BASE_SPEED + s.score * 0.0005;
        const alive = s.marbles.filter((m) => !m.popping);
        alive.forEach((m) => { m.t += s.speed / 1000; });

        // Check if front marble reached hole
        if (alive.length > 0 && alive[alive.length - 1].t >= 0.98) {
          s.lives--;
          if (s.lives <= 0) {
            s.phase = "gameover";
            if (s.score > s.highScore) {
              s.highScore = s.score;
              try { localStorage.setItem(HS_KEY, String(s.score)); } catch {}
            }
          } else {
            // Remove last marble
            const idx = s.marbles.indexOf(alive[alive.length - 1]);
            if (idx !== -1) s.marbles.splice(idx, 1);
          }
        }

        // Pop animations
        s.marbles.forEach((m) => {
          if (m.popping) m.popFrame++;
        });
        s.marbles = s.marbles.filter((m) => !(m.popping && m.popFrame > 15));

        // Win check
        if (s.marbles.filter((m) => !m.popping).length === 0) {
          s.phase = "win";
          if (s.score > s.highScore) {
            s.highScore = s.score;
            try { localStorage.setItem(HS_KEY, String(s.score)); } catch {}
          }
        }

        // Update flying marble
        if (s.flying) {
          s.flying.x += s.flying.vx;
          s.flying.y += s.flying.vy;

          // Check collision with chain marbles
          let inserted = false;
          for (const m of alive) {
            const pos = getPathPos(m.t);
            const dx = s.flying.x - pos.x;
            const dy = s.flying.y - pos.y;
            if (Math.sqrt(dx * dx + dy * dy) < MARBLE_R * 2) {
              // Insert near this marble
              const newMarble: Marble = {
                t: m.t + 0.001,
                color: s.flying.color,
                id: s.idCounter++,
                popping: false,
                popFrame: 0,
              };
              s.marbles.push(newMarble);
              s.flying = null;
              inserted = true;
              checkMatches();
              break;
            }
          }

          if (!inserted && (s.flying.x < 0 || s.flying.x > W || s.flying.y < 0 || s.flying.y > H)) {
            s.flying = null;
          }
        }
      }

      // ΓöÇΓöÇΓöÇ Draw ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
      ctx.fillStyle = "#1a1a2e";
      ctx.fillRect(0, 0, W, H);

      // Draw path
      ctx.beginPath();
      ctx.strokeStyle = "rgba(255,255,255,0.15)";
      ctx.lineWidth = MARBLE_R * 2 + 4;
      ctx.lineCap = "round";
      ctx.lineJoin = "round";
      const startPt = getPathPos(0);
      ctx.moveTo(startPt.x, startPt.y);
      for (let t = 0.01; t <= 1; t += 0.01) {
        const p = getPathPos(t);
        ctx.lineTo(p.x, p.y);
      }
      ctx.stroke();

      // Draw marbles on path
      for (const m of s.marbles) {
        const pos = getPathPos(Math.min(m.t, 0.99));
        const scale = m.popping ? 1 + m.popFrame / 8 : 1;
        const alpha = m.popping ? Math.max(0, 1 - m.popFrame / 15) : 1;
        ctx.globalAlpha = alpha;
        ctx.beginPath();
        ctx.arc(pos.x, pos.y, MARBLE_R * scale, 0, Math.PI * 2);
        ctx.fillStyle = m.color;
        ctx.fill();
        ctx.strokeStyle = "rgba(255,255,255,0.4)";
        ctx.lineWidth = 2;
        ctx.stroke();
        // Shine
        ctx.beginPath();
        ctx.arc(pos.x - 4, pos.y - 4, MARBLE_R * 0.35 * scale, 0, Math.PI * 2);
        ctx.fillStyle = "rgba(255,255,255,0.4)";
        ctx.fill();
        ctx.globalAlpha = 1;
      }

      // Draw hole
      ctx.beginPath();
      ctx.arc(HOLE_X, HOLE_Y, MARBLE_R * 1.5, 0, Math.PI * 2);
      ctx.fillStyle = "#000";
      ctx.fill();
      ctx.strokeStyle = "#555";
      ctx.lineWidth = 3;
      ctx.stroke();

      // Draw shooter
      const barrelLen = 35;
      ctx.save();
      ctx.translate(HOLE_X, HOLE_Y);
      ctx.rotate(s.angle);
      ctx.beginPath();
      ctx.rect(0, -6, barrelLen, 12);
      ctx.fillStyle = "#7f8c8d";
      ctx.fill();
      ctx.restore();

      // Draw current marble in shooter
      ctx.beginPath();
      ctx.arc(HOLE_X, HOLE_Y, MARBLE_R, 0, Math.PI * 2);
      ctx.fillStyle = s.currentColor;
      ctx.fill();
      ctx.strokeStyle = "rgba(255,255,255,0.5)";
      ctx.lineWidth = 2;
      ctx.stroke();

      // Draw next marble preview
      ctx.fillStyle = "rgba(255,255,255,0.7)";
      ctx.font = "12px sans-serif";
      ctx.fillText("NEXT:", 10, H - 35);
      ctx.beginPath();
      ctx.arc(60, H - 30, 12, 0, Math.PI * 2);
      ctx.fillStyle = s.nextColor;
      ctx.fill();

      // Draw flying marble
      if (s.flying) {
        ctx.beginPath();
        ctx.arc(s.flying.x, s.flying.y, MARBLE_R, 0, Math.PI * 2);
        ctx.fillStyle = s.flying.color;
        ctx.fill();
        ctx.strokeStyle = "rgba(255,255,255,0.5)";
        ctx.lineWidth = 2;
        ctx.stroke();
      }

      // HUD
      ctx.fillStyle = "rgba(255,255,255,0.9)";
      ctx.font = "bold 18px sans-serif";
      ctx.fillText(`Score: ${s.score}`, 10, 28);
      ctx.fillText(`Best: ${s.highScore}`, 10, 52);
      for (let i = 0; i < s.lives; i++) {
        ctx.beginPath();
        ctx.arc(W - 20 - i * 28, 20, 10, 0, Math.PI * 2);
        ctx.fillStyle = "#e74c3c";
        ctx.fill();
      }

      // Overlays
      if (s.phase !== "playing") {
        ctx.fillStyle = "rgba(0,0,0,0.6)";
        ctx.fillRect(0, 0, W, H);
        ctx.fillStyle = s.phase === "win" ? "#2ecc71" : "#e74c3c";
        ctx.font = "bold 48px sans-serif";
        ctx.textAlign = "center";
        ctx.fillText(s.phase === "win" ? "YOU WIN!" : "GAME OVER", W / 2, H / 2 - 20);
        ctx.fillStyle = "#fff";
        ctx.font = "22px sans-serif";
        ctx.fillText(`Score: ${s.score}`, W / 2, H / 2 + 25);
        ctx.fillText("Click to restart", W / 2, H / 2 + 60);
        ctx.textAlign = "left";
      }

      setDisplay({ lives: s.lives, score: s.score, highScore: s.highScore, phase: s.phase, currentColor: s.currentColor, nextColor: s.nextColor });
      animRef.current = requestAnimationFrame(loop);
    };

    animRef.current = requestAnimationFrame(loop);
    return () => cancelAnimationFrame(animRef.current);
  }, [checkMatches]);

  const handleCanvasClick = useCallback(() => {
    if (stateRef.current.phase !== "playing") {
      initChain();
    }
  }, [initChain]);

  return (
    <div className="flex flex-col items-center gap-3 select-none">
      <div className="flex gap-6 text-white text-sm font-semibold bg-gray-900 px-4 py-2 rounded-lg flex-wrap justify-center">
        <span className="text-yellow-300">Score: {display.score}</span>
        <span className="text-purple-300">Best: {display.highScore}</span>
        <span className="text-red-400">{"ΓÖÑ".repeat(Math.max(0, display.lives))}</span>
      </div>
      <canvas
        ref={canvasRef}
        width={W}
        height={H}
        onClick={handleCanvasClick}
        style={{ maxWidth: "100%", borderRadius: "12px", cursor: "crosshair", touchAction: "none" }}
      />
      <p className="text-gray-400 text-xs">Click to shoot ΓÇó Match 3+ same color</p>
    </div>
  );
}

